import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Logo, Toast } from './UI';
import { PatientData, CoordinatorProfile } from '../types';
import { QUESTIONS } from '../constants';
import { DataService } from '../services/dataService';

interface DashboardProps {
  profile: CoordinatorProfile;
  onLogout: () => void;
  onEnterEditMode: () => void;
}

const safeBtoa = (str: string) => {
  return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
      function toSolidBytes(match, p1) {
          return String.fromCharCode(parseInt(p1, 16));
  }));
};

const formatDate = (timestamp?: number) => {
    if (!timestamp) return 'Pendiente';
    return new Date(timestamp).toLocaleDateString() + ' ' + new Date(timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
};

// --- TEXTOS DE EJEMPLO MEJORADOS ---
const INTERNAL_CLINICAL_EXAMPLE = `**INFORME DE VALORACIÓN INICIAL & GUÍA TERAPÉUTICA**

**PERFIL PSICOLÓGICO:**
*   **Patrón Cognitivo Predominante:** Rumiación Obsesiva Anticipatoria y Post-evento.
*   **Estilo de Apego Sugerido:** Ansioso-Ambivalente. Alta sensibilidad al rechazo percibido.
*   **Mecanismo de Defensa:** Intelectualización del dolor y evasión mediante distracción externa (intolerancia al silencio/vacío).

**OBSERVACIONES CLAVE (COACHING DE VIDA):**
1.  **Bloqueo de la Acción:** El paciente gasta el 80% de su energía mental en "revisar" el pasado o "temer" el futuro, dejándole sin recursos para el presente.
2.  **Locus de Control Externo:** Su bienestar depende excesivamente de la validación externa (respuestas de mensajes, invitaciones sociales).
3.  **Auto-Concepto:** Se define a sí mismo a través del error ("metí la pata") y no de su potencial.

**ESTRATEGIA RECOMENDADA DE INTERVENCIÓN:**
*   **Fase 1 (Desactivación):** Técnicas de parada de pensamiento y regulación del Sistema Nervioso para reducir la ansiedad basal.
*   **Fase 2 (Reestructuración):** Trabajo sobre la "Herida de Pertenencia". Demostrar que su valor no es negociable.
*   **Fase 3 (Acción):** "Del Miedo al Poder". Ejercicios de exposición gradual al silencio y la toma de decisiones autónomas.

**CONCLUSIÓN PROFESIONAL:**
Paciente con alto potencial de recuperación. Su sensibilidad, actualmente desbordada, es su mayor activo si aprende a canalizarla. Candidato ideal para el programa de "Gestión Emocional Profunda".`;

const EXTERNAL_PATIENT_EXAMPLE = `Hola Martín,

Gracias por la valentía de mirarte en este espejo. Hemos analizado tus respuestas con mucho cuidado y queremos decirte algo importante antes de nada: **No estás roto, y lo que sientes tiene sentido.**

Lo que hemos visto en tu cuestionario no es debilidad, sino una **sensibilidad extraordinaria** que, en este momento de tu vida, está jugando en tu contra. Tienes un radar emocional muy potente, pero ahora mismo está calibrado para detectar "peligros" donde a veces no los hay (un mensaje no respondido, un silencio, una mirada).

**Tu "Niebla" Actual:**
Detectamos que vives atrapado en un bucle agotador: intentas controlar el futuro para evitar el dolor, y repasas el pasado para buscar errores. Eso te deja exhausto y con esa sensación de vacío cuando todo se calla. Tu mente te dice "si me preocupo lo suficiente, estaré a salvo", pero eso es una trampa.

**La Buena Noticia:**
Ese nudo en el estómago y esa rumiación mental no son tu identidad, son solo **mecanismos aprendidos**. Y como todo lo aprendido, se puede desaprender.

**Tu Hoja de Ruta:**
Hemos diseñado una estrategia específica para ti. No queremos cambiar quién eres, queremos enseñarte a **apagar la alarma** de incendio cuando solo hay humo de una vela.

Imagínate por un momento:
*   Poder leer un mensaje (o no recibirlo) y seguir en paz.
*   Disfrutar del silencio sin necesidad de huir.
*   Sentir que perteneces, no porque te inviten, sino porque te tienes a ti mismo.

Martín, tienes todo lo necesario para salir de esta niebla, pero no tienes por qué hacerlo solo. Ya has dado el primer paso al rellenar este cuestionario. El siguiente paso es permitirnos darte las herramientas para recuperar el mando de tu vida.

Te esperamos. Es tu momento.`;

export const CoordinatorDashboard: React.FC<DashboardProps> = ({ profile, onLogout, onEnterEditMode }) => {
  const [patient, setPatient] = useState<Partial<PatientData>>({
    nombre: '', edad: '', sexo: '', observaciones: '', telefono: '', email: ''
  });

  const [phonePrefix, setPhonePrefix] = useState('+34');
  const [phoneBody, setPhoneBody] = useState('');

  const [sendMethods, setSendMethods] = useState({
    email: true,
    whatsapp: false,
    sms: false
  });
  const [linkGenerated, setLinkGenerated] = useState<string | null>(null);
  const [registry, setRegistry] = useState<PatientData[]>([]);
  const [toastMessage, setToastMessage] = useState('');
  const [showToast, setShowToast] = useState(false);

  const [selectedPatientResults, setSelectedPatientResults] = useState<PatientData | null>(null);
  const [selectedPatientConclusion, setSelectedPatientConclusion] = useState<PatientData | null>(null);
  const [selectedPatientDetails, setSelectedPatientDetails] = useState<PatientData | null>(null); 
  const [editingConclusion, setEditingConclusion] = useState('');
  const [editingAudio, setEditingAudio] = useState<string | undefined>(undefined);

  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');

  const statusLabels: Record<string, string> = {
      'all': 'Todos',
      'pending': 'Pendiente',
      'waiting': 'Espera',
      'completed': 'Hecho',
      'concluded': 'Enviado',
      'viewed': 'Visto'
  };

  useEffect(() => {
    try {
        const saved = localStorage.getItem('radar_patients');
        if (saved) {
            setRegistry(JSON.parse(saved));
        } else {
            const sample: PatientData = {
                id: 'sample-martin',
                nombre: 'Martín ejemplo',
                email: 'martin@ejemplo.com',
                edad: '34',
                sexo: 'Hombre',
                observaciones: 'Registro de ejemplo generado automáticamente para visualización.',
                telefono: '+34600123456',
                status: 'completed',
                dateSent: Date.now() - 86400000,
                dateAnswered: Date.now() - 3600000,
                answers: {
                    "1": "b", "1.1": "b", "2": "b", "2.2": "c", "3": "b", "3.3": "4",
                    "4": "b", "4.4": "b", "5": "c", "6": "b", "7": "a"
                },
                conversationSummary: INTERNAL_CLINICAL_EXAMPLE,
                finalConclusion: EXTERNAL_PATIENT_EXAMPLE,
                conclusionViews: 0
            };
            setRegistry([sample]);
        }
    } catch (e) {
        console.error("Error cargando registros", e);
    }
  }, []);

  const triggerToast = (msg: string) => {
    setToastMessage(msg);
    setShowToast(true);
  };

  const saveRegistry = (newRegistry: PatientData[]) => {
    setRegistry(newRegistry);
    localStorage.setItem('radar_patients', JSON.stringify(newRegistry));
  };

  const deleteRecord = (id: string) => {
    if(!confirm("¿Estás seguro? Se borrarán todos los datos del paciente.")) return;
    const updated = registry.filter(r => r.id !== id);
    saveRegistry(updated);
    triggerToast("Registro eliminado correctamente");
  };

  const toggleStatus = (id: string) => {
    const updated = registry.map(r => {
      if (r.id === id) {
        const nextStatus: any = r.status === 'waiting' ? 'pending' : r.status === 'pending' ? 'waiting' : 'pending';
        return { ...r, status: nextStatus };
      }
      return r;
    });
    saveRegistry(updated);
    triggerToast("Estado actualizado");
  };

  const handleGenerateAndSend = (isResend: boolean = false) => {
    if (!patient.nombre || !patient.email) return alert("Nombre y Email son requeridos.");

    const fullPhone = phoneBody ? `${phonePrefix}${phoneBody}`.trim() : '';
    const now = Date.now();

    const payload = { 
      nombre: patient.nombre, 
      email: patient.email,
      telefono: fullPhone, 
      edad: patient.edad, 
      sexo: patient.sexo, 
      coordinatorEmail: profile.email, 
      timestamp: now
    };

    try {
        const idEncoded = safeBtoa(JSON.stringify(payload));
        const baseUrl = window.location.origin + window.location.pathname;
        const url = `${baseUrl}#/session?p=${idEncoded}`;

        setLinkGenerated(url);

        const newRecord: PatientData = { 
          ...patient as PatientData, 
          telefono: fullPhone,
          id: idEncoded, 
          status: 'pending',
          dateSent: now
        };

        const cleanRegistry = registry.filter(r => r.id !== 'sample-martin');
        saveRegistry([...cleanRegistry, newRecord]);

        let subject = "Tu enlace para el Cuestionario Espejo";
        let body = `Hola ${patient.nombre.split(' ')[0]},\n\nAquí tienes tu enlace directo para realizar el Cuestionario Espejo:\n${url}\n\nGracias.`;

        if (isResend) {
            subject = "Actualización Importante: Cuestionario Espejo";
            body = `Hola ${patient.nombre.split(' ')[0]},\n\nEsperamos que estés bien. Nos ponemos en contacto contigo porque hemos actualizado nuestro Cuestionario Espejo con nuevas dinámicas que profundizan mucho más en el bienestar emocional.\n\nTe invitamos a redescubrirte sin compromiso a través de este enlace:\n${url}\n\nUn cordial saludo,\nEl equipo de Naveguemos Juntos.`;
        }

        const smsBody = `Hola ${patient.nombre.split(' ')[0]}, ${isResend ? 'te invitamos a redescubrir el Cuestionario Espejo actualizado:' : 'tu enlace al Cuestionario Espejo:'} ${url}`;

        if (sendMethods.whatsapp && fullPhone) {
          const cleanPhone = fullPhone.replace(/\D/g, '');
          window.open(`https://wa.me/${cleanPhone}?text=${encodeURIComponent(body)}`, '_blank');
        }

        if (sendMethods.email) {
          const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(patient.email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
          window.open(gmailUrl, '_blank');
        }

        if (sendMethods.sms && fullPhone) {
          window.open(`sms:${fullPhone}?body=${encodeURIComponent(smsBody)}`, '_blank');
        }

        triggerToast(isResend ? "Cuestionario reenviado con mensaje de invitación" : "Enlace generado y plataformas abiertas");

    } catch (error) {
        console.error("Error generando enlace", error);
        alert("Error al generar el enlace.");
    }
  };

  const handleResendFromDetails = () => {
      if (!selectedPatientDetails) return;

      const p = selectedPatientDetails;
      setPatient({
          nombre: p.nombre,
          email: p.email,
          edad: p.edad,
          sexo: p.sexo,
          telefono: p.telefono,
          observaciones: p.observaciones
      });

      if (p.telefono && p.telefono.length > 3) {
          setPhonePrefix(p.telefono.substring(0, 3));
          setPhoneBody(p.telefono.substring(3));
      }

      setSelectedPatientDetails(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      setTimeout(() => handleGenerateAndSend(true), 500);
