                      <Button variant="primary" className="px-8 py-3 rounded-xl text-xs" onClick={() => {
                        navigator.clipboard.writeText(linkGenerated);
                        triggerToast("¡Enlace copiado al portapapeles!");
                      }}>
                        Copiar
                      </Button>
                    </div>
                    <p className="text-xs text-center text-teal-600 font-bold uppercase tracking-tight">Copia este enlace si deseas enviarlo por otra vía manual</p>
                  </div>
                )}
              </div>
            </Card>
          </div>
        </div>
      </div>
      <Toast message={toastMessage} visible={showToast} onHide={() => setShowToast(false)} />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { DataService } from '../services/dataService'; // Importamos el servicio
