                        <Button onClick={requestExit} variant="outline" className={`w-full border-blue-600 text-blue-600 hover:bg-blue-50 ${isDarkMode ? 'border-white/20 text-white hover:bg-white/10' : ''}`}>Finalizar</Button>
                    </div>
