              </div>
            </div>
            <div className="flex gap-4 pt-6 border-t border-white/10 mt-6"><Button className="flex-1 py-4 text-lg" onClick={saveQuestionChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black hover:bg-white/5" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  // Se han eliminado decodeAudioData, decodeBase64 y generateSpeechBlock
  // para cumplir estrictamente con la eliminación de voces IA.

  async summarizeSession(patient: any, answers: any, transcript: string): Promise<string> {
    try {
      // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Resume esta sesión de Cuestionario Espejo. Paciente: ${patient.nombre}. Respuestas: ${JSON.stringify(answers)}. Contexto: ${transcript}. Genera valoración de estado mental relevante para el profesional.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      // Access .text property directly instead of calling it as a method.
      return response.text || "";
    } catch (e) {
      console.error("Error generating session summary:", e);
      return "No se pudo generar el resumen automáticamente.";
    }
  }
}

export const gemini = new GeminiService();

