import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  async summarizeSession(patient: any, answers: any, transcript: string): Promise<string> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Prompte mejorado para actuar como experto psicoterapeuta y coach emocional
      const prompt = `
        Actúa como un psicoterapeuta experto especializado en autoestima y procesos depresivos, y un Coach Emocional de alto nivel.
        Debes analizar los resultados de una sesión del "Cuestionario Espejo".

        DATOS DEL PACIENTE:
        Nombre: ${patient.nombre}
        Edad: ${patient.edad}
        Respuestas al cuestionario: ${JSON.stringify(answers)}
        Transcripción de la interacción: ${transcript}

        INSTRUCCIONES DE FORMATO Y ESTILO:
        1. NO utilices asteriscos (*), ni guiones (-) ni símbolos de Markdown para listas.
        2. Redacta en párrafos claros y fluidos, con títulos en mayúsculas.
        3. El tono debe ser humano, cálido, profesional y profundamente empático.
        4. Evita que parezca generado por una IA; debe parecer redactado por un clínico veterano.

        ESTRUCTURA DEL INFORME TÉCNICO (Uso interno profesional):
        - VALORACIÓN DEL ESTADO EMOCIONAL: Un análisis profundo de su rumiación, autoestima y posibles signos depresivos.
        - DINÁMICA DE PENSAMIENTO: Cómo su mente construye sus miedos.
        - ESTRATEGIA DE COACHING EMOCIONAL: Incluye 3 puntos específicos de intervención sobre su diálogo interno y gestión de emociones.
        - RECOMENDACIÓN TERAPÉUTICA: Sugiere si el enfoque debe ser TCC, ACT, Mindfulness o sistémico basándote en su perfil.

        Sé extenso y detallado. Confío en tu asesoramiento experto para que el informe ayude a nuestros profesionales a ofrecer el mejor tratamiento.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', // Usamos el modelo Pro para mayor capacidad de razonamiento clínico
        contents: prompt,
      });

      return response.text || "No se pudo generar la valoración automática.";
    } catch (e) {
      console.error("Error generating session summary:", e);
      return "Error de conexión con el motor de análisis clínico.";
    }
  }
}

