  };

  const saveRegistry = (newRegistry: PatientData[]) => {
    setRegistry(newRegistry);
    localStorage.setItem('radar_patients', JSON.stringify(newRegistry));
  };

  const deleteRecord = (id: string) => {
    if(!confirm("¿Estás seguro? Se borrarán todos los datos del paciente.")) return;
    const updated = registry.filter(r => r.id !== id);
    saveRegistry(updated);
    triggerToast("Registro eliminado correctamente");
  };

  const toggleStatus = (id: string) => {
    const updated = registry.map(r => {
      if (r.id === id) {
        // Solo permitimos el cambio manual de Pendiente a Enviado desde la lista rápida
        if (r.status === 'pending') {
            return { ...r, status: 'sent' as const };
        }
      }
      return r;
    });
    saveRegistry(updated);
