        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer 
            className="fixed bottom-0 left-0 right-0 p-4 border-t z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] no-print bg-cover bg-center"
