                    "1": "b", "1.1": "b", "2": "b", "2.2": "c", "3": "b", "3.3": "4",
                    "4": "b", "4.4": "b", "5": "c", "6": "b", "7": "d", "8": "c",
                    "9": "c", "10": "b", "11": "e", "12": "d"
                },
                conversationSummary: INTERNAL_CLINICAL_EXAMPLE,
                finalConclusion: EXTERNAL_PATIENT_EXAMPLE,
                conclusionViews: 0
            };
            setRegistry([sample]);
        }
    } catch (e) {
        console.error("Error cargando registros", e);
    }
  }, []);

  const triggerToast = (msg: string) => {
    setToastMessage(msg);
    setShowToast(true);
  };

  const saveRegistry = (newRegistry: PatientData[]) => {
    setRegistry(newRegistry);
    localStorage.setItem('radar_patients', JSON.stringify(newRegistry));
  };

  const deleteRecord = (id: string) => {
    if(!confirm("¿Estás seguro? Se borrarán todos los datos del paciente.")) return;
    const updated = registry.filter(r => r.id !== id);
    saveRegistry(updated);
    triggerToast("Registro eliminado correctamente");
  };

  const toggleStatus = (id: string) => {
    const updated = registry.map(r => {
      if (r.id === id) {
        if (r.status === 'pending') {
            return { ...r, status: 'sent' as const };
        }
      }
      return r;
    });
    saveRegistry(updated);
    const changed = registry.find(r => r.id === id)?.status === 'pending';
    if (changed) triggerToast("Estado actualizado a ENVIADO");
  };

  const getBaseUrl = () => {
    // Método más fiable para Vercel y entornos con subdirectorios o hashes
    return window.location.href.split('#')[0].split('?')[0];
  };

  const handleGenerateAndSend = (isResend: boolean = false) => {
    if (!patient.nombre || !patient.email) return alert("Nombre y Email son requeridos.");

    const fullPhone = phoneBody ? `${phonePrefix}${phoneBody}`.trim() : '';
    const now = Date.now();

    const payload = { 
      nombre: patient.nombre, 
      email: patient.email,
      telefono: fullPhone, 
      edad: patient.edad, 
      sexo: patient.sexo, 
      coordinatorEmail: profile.email, 
      timestamp: now
    };

    try {
        const idEncoded = safeBtoa(JSON.stringify(payload));
        const baseUrl = getBaseUrl();
        const url = `${baseUrl}#/session?p=${idEncoded}`;

        setLinkGenerated(url);

        const newRecord: PatientData = { 
          ...patient as PatientData, 
          telefono: fullPhone,
          id: idEncoded, 
          status: 'pending', 
          dateSent: now
        };

        saveRegistry([...registry, newRecord]);

        let subject = "Tu enlace para el Cuestionario Espejo";
        let body = `Hola ${patient.nombre.split(' ')[0]},\n\nAquí tienes tu enlace directo para realizar el Cuestionario Espejo:\n${url}\n\nGracias.`;

        if (isResend) {
            subject = "Actualización Importante: Cuestionario Espejo";
            body = `Hola ${patient.nombre.split(' ')[0]},\n\nEsperamos que estés bien. Nos ponemos en contacto contigo porque hemos actualizado nuestro Cuestionario Espejo con nuevas dinámicas que profundizan mucho más en el bienestar emocional.\n\nTe invitamos a redescubrirte sin compromiso a través de este enlace:\n${url}\n\nUn cordial saludo,\nEl equipo de Naveguemos Juntos.`;
        }

        if (sendMethods.whatsapp && fullPhone) {
          const cleanPhone = fullPhone.replace(/\D/g, '');
          window.open(`https://wa.me/${cleanPhone}?text=${encodeURIComponent(body)}`, '_blank');
        }

        if (sendMethods.email) {
          const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(patient.email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
          window.open(gmailUrl, '_blank');
        }

        if (sendMethods.sms && fullPhone) {
           const smsBody = `Hola ${patient.nombre.split(' ')[0]}, tu enlace al Cuestionario Espejo: ${url}`;
           window.open(`sms:${fullPhone}?body=${encodeURIComponent(smsBody)}`, '_blank');
        }

        triggerToast(isResend ? "Cuestionario reenviado" : "Enlace generado y notificado.");

    } catch (error) {
        console.error("Error generando enlace", error);
        alert("Error al generar el enlace.");
    }
  };

  const handleResendFromDetails = () => {
      if (!selectedPatientDetails) return;
      const p = selectedPatientDetails;
      setPatient({ nombre: p.nombre, email: p.email, edad: p.edad, sexo: p.sexo, telefono: p.telefono, observaciones: p.observaciones });
      if (p.telefono && p.telefono.length > 3) {
          setPhonePrefix(p.telefono.substring(0, 3));
          setPhoneBody(p.telefono.substring(3));
      }
      setSelectedPatientDetails(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      setTimeout(() => handleGenerateAndSend(true), 500);
  };

  const openResultsModal = (p: PatientData) => setSelectedPatientResults(p);
  const openConclusionModal = (p: PatientData) => {
    setSelectedPatientConclusion(p);
    setEditingConclusion(p.finalConclusion || EXTERNAL_PATIENT_EXAMPLE);
    setEditingAudio(p.audioConclusion);
  };

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file && file.size <= 1048576) {
          const reader = new FileReader();
          reader.onload = (ev) => setEditingAudio(ev.target?.result as string);
          reader.readAsDataURL(file);
      } else if (file) {
          alert("Audio demasiado grande (Max 1MB)");
      }
  };

  const handleSaveConclusion = () => {
    if (!selectedPatientConclusion) return;
    const updated = registry.map(r => r.id === selectedPatientConclusion.id ? { ...r, finalConclusion: editingConclusion, audioConclusion: editingAudio } : r);
    saveRegistry(updated);
    setSelectedPatientConclusion({ ...selectedPatientConclusion, finalConclusion: editingConclusion, audioConclusion: editingAudio });
    triggerToast("Conclusión guardada correctamente");
  };

  const handleEditDetails = () => {
      if (selectedPatientDetails) {
          setTempPatientDetails(selectedPatientDetails);
          setIsEditingDetails(true);
      }
  };

  const handleSaveDetails = () => {
      if (!tempPatientDetails) return;
      const updated = registry.map(r => r.id === tempPatientDetails.id ? tempPatientDetails : r);
      saveRegistry(updated);
      setSelectedPatientDetails(tempPatientDetails);
      setIsEditingDetails(false);
      triggerToast("Ficha actualizada");
  };

  const getConclusionUrlAndBody = (p: PatientData) => {
    const baseUrl = getBaseUrl();
    const url = `${baseUrl}#/conclusion?id=${encodeURIComponent(p.id)}`;
    const body = `Hola ${p.nombre.split(' ')[0]},\n\nYa están disponibles tus resultados y la conclusión detallada de tu Cuestionario Espejo.\n\nPuedes acceder a través de este enlace personalizado:\n${url}\n\nIMPORTANTE: Por seguridad, este enlace permite solo DOS (2) visualizaciones.`;
    return { url, body };
  };

  const markAsConcluded = (id: string) => {
      const updated = registry.map(r => r.id === id ? { ...r, status: 'concluded' as const, dateConclusionSent: Date.now(), conclusionViews: 0 } : r);
      saveRegistry(updated);
  };

  const handleSendConclusionLink = () => {
    if (!selectedPatientConclusion) return;
    const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
    const subject = "Resultados y Análisis - Cuestionario Espejo";
    const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(selectedPatientConclusion.email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.open(gmailUrl, '_blank');
    markAsConcluded(selectedPatientConclusion.id);
    triggerToast("Gmail abierto.");
  };

  const handleSendConclusionWhatsApp = () => {
    if (!selectedPatientConclusion || !selectedPatientConclusion.telefono) return alert("Falta teléfono.");
    const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
    const cleanPhone = selectedPatientConclusion.telefono.replace(/\D/g, '');
    window.open(`https://wa.me/${cleanPhone}?text=${encodeURIComponent(body)}`, '_blank');
    markAsConcluded(selectedPatientConclusion.id);
    triggerToast("WhatsApp abierto.");
  };

