                .header { border-bottom: 4px solid #1e3a8a; padding-bottom: 15px; margin-bottom: 25px; display: flex; justify-content: space-between; align-items: flex-end; }
                .logo-text { font-size: 26px; font-weight: bold; color: #1e3a8a; }
                .logo-sub { font-size: 12px; text-transform: uppercase; letter-spacing: 2px; color: #2563eb; }
                .section-title { font-size: 12px; font-weight: 800; text-transform: uppercase; color: #64748b; letter-spacing: 1px; border-bottom: 1px solid #e2e8f0; padding-bottom: 5px; margin-bottom: 15px; }

