                    </td>
                    <td style="width: 33%;">
                        <span class="label">Perfil</span>
                        <span class="value">${p.edad} años<br>${p.sexo}</span>
                    </td>
                </tr>
                <tr>
                    <td>
                        <span class="label">Fecha Alta</span>
                        <span class="value">${formatDate(p.dateSent)}</span>
                    </td>
                    <td>
                        <span class="label">Fecha Respuesta</span>
                        <span class="value">${formatDate(p.dateAnswered)}</span>
                    </td>
                    <td>
                        <span class="label">Estado Actual</span>
                        <span class="value" style="color:#2563eb; text-transform:uppercase;">${p.status}</span>
                    </td>
                </tr>
            </table>

            <div class="section-title">Observaciones Iniciales</div>
            <div style="font-size: 13px; font-style: italic; margin-bottom: 30px; padding: 10px; background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px;">
                ${p.observaciones || "Sin observaciones registradas."}
            </div>

            <div class="section-title">Valoración Clínica / Coaching (Uso Interno)</div>
            <div class="report-box">${p.conversationSummary || "Pendiente de valoración técnica."}</div>

            <div class="footer">Documento privado. Uso exclusivo para profesionales autorizados.</div>
            <script>setTimeout(() => { window.print(); }, 500);</script>
        </body>
        </html>
    `;
    printWindow.document.open();
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const filteredRegistry = registry.filter(p => {
      const matchesSearch = searchTerm === '' || p.nombre.toLowerCase().includes(searchTerm.toLowerCase()) || p.email.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'all' || p.status === filterStatus;
      const pDate = p.dateSent || 0;
      const startMs = dateStart ? new Date(dateStart).getTime() : 0;
      const endMs = dateEnd ? new Date(dateEnd).setHours(23,59,59,999) : Infinity;
      return matchesSearch && matchesStatus && (pDate >= startMs && pDate <= endMs);
  });

  return (
    <div className="min-h-screen overflow-y-auto relative">
      <div className="absolute inset-0 pointer-events-none opacity-20 bg-cover bg-center -z-10" style={{backgroundImage: "url('https://images.unsplash.com/photo-1516550893923-42d28e5677af?q=80&w=2070&auto=format&fit=crop')"}}></div>

      {/* MODAL FICHA PACIENTE */}
      {selectedPatientDetails && (
          <div className="fixed inset-0 z-[120] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
             <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-6 border-b flex justify-between items-center bg-blue-900 text-white">
                    <h2 className="text-2xl font-bold flex items-center gap-3"><i className="fas fa-user-circle"></i> Ficha del Paciente</h2>
                    <div className="flex gap-2">
                         {!isEditingDetails && <button onClick={handleEditDetails} className="text-blue-200 hover:text-white mr-4"><i className="fas fa-edit text-xl"></i></button>}
                         <button onClick={() => { setSelectedPatientDetails(null); setIsEditingDetails(false); }} className="text-blue-200 hover:text-white text-2xl"><i className="fas fa-times"></i></button>
                    </div>
                </div>

                <div className="p-8 overflow-y-auto space-y-8">
                    {isEditingDetails && tempPatientDetails ? (
                         <div className="space-y-6">
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <Input label="Nombre" value={tempPatientDetails.nombre} onChange={e => setTempPatientDetails({...tempPatientDetails, nombre: e.target.value})} />
                                <Input label="Email" value={tempPatientDetails.email} onChange={e => setTempPatientDetails({...tempPatientDetails, email: e.target.value})} />
                                <Input label="Teléfono" value={tempPatientDetails.telefono} onChange={e => setTempPatientDetails({...tempPatientDetails, telefono: e.target.value})} />
                                <div className="grid grid-cols-2 gap-4">
                                    <Input label="Edad" value={tempPatientDetails.edad} onChange={e => setTempPatientDetails({...tempPatientDetails, edad: e.target.value})} />
                                    <div className="space-y-1">
                                        <label className="text-xs font-bold text-slate-500 uppercase">Sexo</label>
                                        <select className="w-full p-3 border rounded-lg bg-slate-50 font-bold" value={tempPatientDetails.sexo} onChange={e => setTempPatientDetails({...tempPatientDetails, sexo: e.target.value})}>
                                            <option value="Mujer">Mujer</option><option value="Hombre">Hombre</option>
                                        </select>
                                    </div>
                                </div>
                             </div>
                             <textarea className="w-full p-4 border rounded-xl bg-slate-50 h-32 text-sm italic" placeholder="Observaciones..." value={tempPatientDetails.observaciones} onChange={e => setTempPatientDetails({...tempPatientDetails, observaciones: e.target.value})} />
                             <textarea className="w-full p-4 border rounded-xl bg-blue-50/50 h-64 text-sm font-medium" placeholder="Valoración clínica..." value={tempPatientDetails.conversationSummary} onChange={e => setTempPatientDetails({...tempPatientDetails, conversationSummary: e.target.value})} />
                         </div>
                    ) : (
                        <>
                            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 grid grid-cols-2 gap-8">
                                <div><span className="label">Nombre Completo</span><span className="value">{selectedPatientDetails.nombre}</span></div>
                                <div><span className="label">Contacto</span><span className="value">{selectedPatientDetails.email}<br/>{selectedPatientDetails.telefono || 'N/A'}</span></div>
                                <div><span className="label">Edad / Sexo</span><span className="value">{selectedPatientDetails.edad} años / {selectedPatientDetails.sexo}</span></div>
                                <div><span className="label">Historial</span><div className="text-xs text-slate-600"><p>Alta: {formatDate(selectedPatientDetails.dateSent)}</p><p>Resp: {formatDate(selectedPatientDetails.dateAnswered)}</p></div></div>
                            </div>
                            <div>
                                <h3 className="text-lg font-black text-blue-900 uppercase tracking-widest border-b pb-2 mb-4">Valoración Clínica / Coaching</h3>
                                <div className="prose prose-slate max-w-none text-slate-700 leading-relaxed whitespace-pre-line p-5 bg-blue-50/30 rounded-xl border border-blue-100 italic">
                                    {selectedPatientDetails.conversationSummary || "Sin valoración."}
