                <div className="p-6 border-t bg-slate-50 flex items-center gap-4">
                    {isEditingDetails ? (
                        <><Button onClick={handleSaveDetails} className="bg-green-600 hover:bg-green-700">Guardar</Button><Button onClick={() => setIsEditingDetails(false)} variant="outline">Cancelar</Button></>
                    ) : (
                        <><Button onClick={handleResendFromDetails} className="bg-blue-600 hover:bg-blue-700 mr-auto"><i className="fas fa-redo mr-2"></i> Reenviar</Button><Button onClick={handlePrintPatientFile}><i className="fas fa-print mr-2"></i> Imprimir Ficha PDF</Button></>
                    )}
