      {/* SEARCH MODAL */}
      {isSearchOpen && (
          <div className="fixed inset-0 z-[150] bg-black/60 flex items-start justify-center pt-24 p-4 backdrop-blur-sm">
              <Card className="w-full max-w-2xl">
                  <div className="flex justify-between items-center mb-6">
                      <h3 className="text-xl font-bold">Búsqueda Avanzada</h3>
                      <button onClick={() => setIsSearchOpen(false)}><i className="fas fa-times text-slate-400 text-xl"></i></button>
