                          <label className="block text-[11px] font-black uppercase text-slate-500 mb-2 tracking-widest">Fecha entre : ------- y ------- .</label>
                          <div className="flex gap-4">
                              <input type="date" className="flex-1 p-3 rounded-xl border-2 border-slate-100 bg-white font-bold" value={dateStart} onChange={e => setDateStart(e.target.value)} />
                              <input type="date" className="flex-1 p-3 rounded-xl border-2 border-slate-100 bg-white font-bold" value={dateEnd} onChange={e => setDateEnd(e.target.value)} />
                          </div>
                      </div>
                      <div className="flex flex-wrap gap-2">
                          {['all', 'pending', 'sent', 'completed', 'concluded', 'finalized'].map(s => (
                              <button key={s} onClick={() => setFilterStatus(s)} className={`px-3 py-2 rounded-lg text-xs font-bold uppercase ${filterStatus === s ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>{statusLabels[s]}</button>
