        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          <div className="lg:col-span-4 space-y-8">
            <Card className="border-teal-100 border-2 shadow-xl">
              <h2 className="text-2xl font-bold mb-6 text-blue-900 border-b pb-4">Especialista</h2>
              <div className="flex items-center gap-5 p-4 bg-teal-50/50 rounded-2xl mb-6">
                <div className="w-14 h-14 bg-blue-900 text-white rounded-xl flex items-center justify-center text-xl font-black">{profile.nombre.charAt(0)}</div>
                <div><p className="font-bold text-slate-800">{profile.nombre}</p><p className="text-xs text-teal-600 font-bold">{profile.email}</p></div>
              </div>
              <Button variant="outline" className="w-full mb-3" onClick={onEnterEditMode}><i className="fas fa-edit mr-2"></i> Editar Cuestionario</Button>
              <div className="mt-10">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="font-black text-xs uppercase text-slate-400 tracking-widest">Registros ({filteredRegistry.length})</h3>
                  <button onClick={() => setIsSearchOpen(true)} className="p-2 bg-slate-100 rounded-lg"><i className="fas fa-search"></i></button>
                </div>
                <div className="space-y-3">
                  {filteredRegistry.slice().reverse().map((p) => (
                    <div key={p.id} className="p-4 bg-white rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition-all">
                      <div className="flex justify-between items-start mb-2">
                        <button onClick={() => setSelectedPatientDetails(p)} className="text-sm font-bold text-blue-700 hover:underline text-left">{p.nombre}</button>
                        <span className={`text-[9px] font-bold uppercase px-2 py-1 rounded-lg ${p.status === 'completed' ? 'bg-teal-50 text-teal-700' : 'bg-slate-100 text-slate-500'}`}>{statusLabels[p.status]}</span>
                      </div>
