                    <div className="flex gap-6">
                        <label className="flex items-center gap-2 cursor-pointer"><input type="checkbox" checked={sendMethods.email} onChange={e => setSendMethods({...sendMethods, email: e.target.checked})} /><span className="text-sm font-bold">Email</span></label>
                        <label className="flex items-center gap-2 cursor-pointer"><input type="checkbox" checked={sendMethods.whatsapp} onChange={e => setSendMethods({...sendMethods, whatsapp: e.target.checked})} /><span className="text-sm font-bold">WhatsApp</span></label>
