import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo } from './UI';
import { PatientData } from '../types';

interface ConclusionPatientViewProps {
  patientId: string;
}

export const ConclusionPatientView: React.FC<ConclusionPatientViewProps> = ({ patientId }) => {
  const [patient, setPatient] = useState<PatientData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [expired, setExpired] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Cargar pacientes
    const loadData = () => {
        try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                const registry: PatientData[] = JSON.parse(saved);
                const found = registry.find(p => p.id === patientId);

                if (found) {
                    const views = found.conclusionViews || 0;

                    if (views >= 2) {
                        setExpired(true);
                        setLoading(false);
                    } else {
                        // Incrementar contador y marcar como FINALIZADO
                        const updated = registry.map(p => {
                            if (p.id === patientId) {
                                return { 
                                    ...p, 
                                    conclusionViews: (p.conclusionViews || 0) + 1,
                                    status: 'finalized' as const, 
                                    dateConclusionViewed: Date.now()
                                };
                            }
                            return p;
                        });
                        localStorage.setItem('radar_patients', JSON.stringify(updated));
                        setPatient(found);
                        setLoading(false);
                    }
                } else {
                    setError("No se ha encontrado el registro.");
                    setLoading(false);
                }
            } else {
                 setError("Base de datos no disponible.");
                 setLoading(false);
            }
        } catch (e) {
            setError("Error al cargar la conclusión.");
            setLoading(false);
        }
    };

    loadData();
  }, [patientId]);

  const handleBooking = () => {
    window.location.href = "https://example.com/reserva"; 
  };

  const handleLearnMore = () => {
    window.location.href = "https://example.com/terapias";
  };

  const handlePlayAudio = () => {
      if (audioRef.current) {
          audioRef.current.play();
      }
  };

  if (loading) {
    return (
        <div className="min-h-screen flex items-center justify-center bg-[#faf9f6]">
            <div className="animate-spin w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full"></div>
        </div>
    );
  }

  if (expired) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-[#faf9f6] p-4">
           <Card className="text-center max-w-lg w-full py-12 px-8">
               <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl">
                   <i className="fas fa-lock"></i>
               </div>
               <h2 className="text-2xl font-bold text-slate-800 mb-4">Enlace Caducado</h2>
               <p className="text-slate-500 mb-8 leading-relaxed">
                   Como se indicaba en el mensaje, este enlace tenía un límite de visualizaciones por seguridad y privacidad, el cual se ha alcanzado.
               </p>
               <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100 mb-8">
                   <p className="text-sm font-bold text-blue-800 mb-2">¿Deseas continuar tu proceso?</p>
                   <p className="text-xs text-blue-600">Reserva ahora el tratamiento que consideres tras las conclusiones obtenidas.</p>
               </div>
               <Button onClick={handleBooking} className="w-full py-4 text-lg animate-pulse shadow-xl bg-gradient-to-r from-blue-600 to-indigo-600 border-none">Reserva Ahora</Button>
           </Card>
        </div>
      );
  }

  if (error || !patient) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-[#faf9f6]">
            <div className="text-center">
                <h2 className="text-xl font-bold text-slate-800 mb-2">Error</h2>
                <p className="text-slate-500">{error}</p>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#faf9f6] relative font-sans">
