            style={{ 
                backgroundImage: "url('assets/fondoconclusion.webp')",
                opacity: 0.8
            }}
        >
            <div className="absolute inset-0 bg-white/40 backdrop-blur-sm"></div>
        </div>

        {patient.audioConclusion && (
            <audio ref={audioRef} src={patient.audioConclusion} className="hidden" />
        )}

        <div className="max-w-4xl mx-auto relative z-10 p-4 md:p-8">
            <div className="mb-10 text-center animate-in fade-in slide-in-from-top-4">
                <Logo />
            </div>

            <Card className="mb-12 border-none shadow-2xl overflow-hidden relative animate-in zoom-in-95 duration-700">
                <div className="bg-gradient-to-r from-blue-900 to-indigo-900 p-8 md:p-14 text-white relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-8 opacity-10 text-9xl">
