// Credenciales Maestras
const MASTER_USER = {
  email: 'cuestionarioespejo@gmail.com',
  pin: '66099',
  nombre: 'Administrador Maestro'
};

const ACCESS_CODE_SECRET = '66099';

// Decodificador seguro para leer el Base64 generado en CoordinatorDashboard (con soporte UTF-8)
const safeAtob = (str: string) => {
  try {
      // Los navegadores a veces convierten '+' en ' ' al leer URLSearchParams
      const normalizedStr = str.replace(/ /g, '+');
      return decodeURIComponent(atob(normalizedStr).split('').map(function(c) {
          return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));
  } catch (e) {
      console.error("Error decodificando safeAtob", e);
      // Fallback para enlaces antiguos
      return atob(str.replace(/ /g, '+'));
  }
};

const App: React.FC = () => {
  const [view, setView] = useState<View>('LANDING');
  const [patientData, setPatientData] = useState<Partial<PatientData>>({});
  const [coordinator, setCoordinator] = useState<CoordinatorProfile | null>(null);
  const [isEditorMode, setIsEditorMode] = useState(false);
  const [conclusionPatientId, setConclusionPatientId] = useState<string | null>(null);

  // Nuevo estado ACCESS_CODE al inicio
  const [authStep, setAuthStep] = useState<'ACCESS_CODE' | 'EMAIL' | 'LOGIN_PIN' | 'REGISTER' | 'RECOVERY' | 'RESET_PIN'>('ACCESS_CODE');

  const [accessCodeInput, setAccessCodeInput] = useState('');
  const [emailInput, setEmailInput] = useState('');
  const [pinInput, setPinInput] = useState('');
  const [toast, setToast] = useState({ show: false, msg: '' });

  const [regForm, setRegForm] = useState({
    nombre: '',
    pin: '',
    confirmPin: '',
    question: '',
    answer: ''
  });
  const [recoveryAnswer, setRecoveryAnswer] = useState('');
  const [currentUserData, setCurrentUserData] = useState<AuthUser | null>(null);

  useEffect(() => {
    // Verificar si ya metió el código de acceso previamente en esta sesión
    const accessGranted = sessionStorage.getItem('radar_access_granted') === 'true';
    if (accessGranted && authStep === 'ACCESS_CODE') {
        setAuthStep('EMAIL');
    }

    const authStatus = localStorage.getItem('radar_auth') === 'true';
    const savedProfile = localStorage.getItem('radar_coordinator');
    if (authStatus && savedProfile) {
      setCoordinator(JSON.parse(savedProfile));
      setView('COORDINATOR');
    }

    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/session')) {
        const parts = hash.split('?');
        if (parts.length > 1) {
            const params = new URLSearchParams(parts[1]);
            const pEncoded = params.get('p');
            if (pEncoded) {
              try {
                // Usamos el decodificador seguro
                const decodedText = safeAtob(pEncoded);
                const decoded = JSON.parse(decodedText);
                setPatientData(decoded);
                setIsEditorMode(false);
                setView('PATIENT_SESSION');
              } catch (e) {
                console.error("Link de sesión no válido", e);
                setView('LANDING');
              }
            }
        }
      } else if (hash.startsWith('#/conclusion')) {
          const parts = hash.split('?');
          if (parts.length > 1) {
              const params = new URLSearchParams(parts[1]);
              const id = params.get('id');
              if (id) {
                  setConclusionPatientId(id);
                  setView('CONCLUSION_VIEW');
              } else {
                  setView('LANDING');
              }
          }
      } else if (hash === '#/coordinator') {
        if (localStorage.getItem('radar_auth') === 'true') {
          setView('COORDINATOR');
        } else {
          setView('LANDING');
          // Si intenta ir a coordinador sin login, lo mandamos al inicio (Access code o Email)
          window.location.hash = '';
        }
      } else if (!hash || hash === '#/') {
        setView('LANDING');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const showToast = (msg: string) => {
    setToast({ show: true, msg });
  };

  const getUsers = (): Record<string, AuthUser> => {
    return JSON.parse(localStorage.getItem('radar_users_db') || '{}');
  };

  const saveUser = (user: AuthUser) => {
    const db = getUsers();
    db[user.email] = user;
    localStorage.setItem('radar_users_db', JSON.stringify(db));
  };

  const handleAccessCodeSubmit = () => {
      if (accessCodeInput === ACCESS_CODE_SECRET) {
          sessionStorage.setItem('radar_access_granted', 'true');
          setAuthStep('EMAIL');
          showToast("Código aceptado");
      } else {
          showToast("Código de acceso incorrecto");
          setAccessCodeInput('');
      }
  };

  const handleEmailSubmit = () => {
    if (!emailInput.includes('@') || !emailInput.includes('.')) {
      return showToast("Introduce un email válido");
    }

    const normalizedEmail = emailInput.trim().toLowerCase();

    if (normalizedEmail === MASTER_USER.email) {
      setAuthStep('LOGIN_PIN');
      return;
    }

    const db = getUsers();
    if (db[normalizedEmail]) {
      setCurrentUserData(db[normalizedEmail]);
      setAuthStep('LOGIN_PIN');
    } else {
      setAuthStep('REGISTER');
    }
  };

  const handlePinLogin = () => {
    const normalizedEmail = emailInput.trim().toLowerCase();
    if (normalizedEmail === MASTER_USER.email) {
      if (pinInput === MASTER_USER.pin) {
        loginSuccess(MASTER_USER.nombre, MASTER_USER.email);
      } else {
        showToast("PIN Maestro incorrecto");
      }
      return;
    }
    if (currentUserData) {
      if (pinInput === currentUserData.pin) {
        loginSuccess(currentUserData.nombre, currentUserData.email);
      } else {
        showToast("PIN incorrecto");
      }
    }
  };

  const handleRegister = () => {
    const { nombre, pin, confirmPin, question, answer } = regForm;

    if (!nombre || !pin || !question || !answer) return showToast("Todos los campos son obligatorios");
    if (!/^\d{4,6}$/.test(pin)) return showToast("El PIN debe tener entre 4 y 6 dígitos numéricos");
    if (pin !== confirmPin) return showToast("Los PIN no coinciden");

    const newUser: AuthUser = {
      email: emailInput.trim().toLowerCase(),
      nombre,
      pin,
      securityQuestion: question,
      securityAnswer: answer.trim().toLowerCase()
    };

    saveUser(newUser);
    showToast("Registro completado con éxito");
    loginSuccess(newUser.nombre, newUser.email);
  };

  const handleRecoveryCheck = () => {
    if (!currentUserData) return;
    if (recoveryAnswer.trim().toLowerCase() === currentUserData.securityAnswer) {
      setAuthStep('RESET_PIN');
      setRegForm({ ...regForm, pin: '', confirmPin: '' });
    } else {
      showToast("Respuesta incorrecta");
    }
  };

  const handleResetPin = () => {
    if (!currentUserData) return;
    const { pin, confirmPin } = regForm;
    if (!/^\d{4,6}$/.test(pin)) return showToast("El PIN debe tener entre 4 y 6 dígitos");
    if (pin !== confirmPin) return showToast("Los PIN no coinciden");

    const updatedUser = { ...currentUserData, pin };
    saveUser(updatedUser);
    setCurrentUserData(updatedUser);
    showToast("PIN actualizado correctamente");
    setAuthStep('LOGIN_PIN');
    setPinInput('');
  };

  const loginSuccess = (nombre: string, email: string) => {
    const profile = { nombre, email };
    localStorage.setItem('radar_auth', 'true');
    localStorage.setItem('radar_coordinator', JSON.stringify(profile));
    setCoordinator(profile);
    setView('COORDINATOR');
    window.location.hash = '#/coordinator';
    setEmailInput('');
    setPinInput('');
    setRegForm({ nombre: '', pin: '', confirmPin: '', question: '', answer: '' });
  };

  const handleLogout = () => {
    localStorage.removeItem('radar_auth');
    localStorage.removeItem('radar_coordinator');
    setCoordinator(null);
    setView('LANDING');
    // Al salir, pedimos de nuevo el código si se cierra sesión completa
    sessionStorage.removeItem('radar_access_granted'); 
    setAuthStep('ACCESS_CODE');
    setEmailInput('');
    setPinInput('');
    setAccessCodeInput('');
    window.location.hash = '';
  };

  const enterEditMode = () => {
    setIsEditorMode(true);
    setView('PATIENT_SESSION');
  };

  return (
    // IMPORTANTE: Eliminado overflow-y-auto para restaurar el scroll nativo de la ventana
    <div className="min-h-screen text-slate-800 overflow-x-hidden font-sans bg-[#faf9f6]">
      {view === 'LANDING' && (
        <div className="min-h-screen flex items-center justify-center flex-col p-6 text-center space-y-8 animate-in fade-in duration-1000 pb-20 relative">

           {/* Decoración de fondo sutil para Landing */}
           <div className="absolute inset-0 pointer-events-none opacity-30 bg-cover bg-center" style={{backgroundImage: "url('https://images.unsplash.com/photo-1516550893923-42d28e5677af?q=80&w=2070&auto=format&fit=crop')"}}></div>

           <div className="max-w-xl w-full relative z-10">
             <Logo />

             {authStep === 'ACCESS_CODE' && (
                <Card className="mt-12 animate-in zoom-in-95 duration-500 shadow-2xl border-white/80 bg-white/90">
                    <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4 text-xl">
                        <i className="fas fa-lock"></i>
                    </div>
                    <h3 className="text-2xl font-bold text-blue-900 mb-2">Acceso Coordinador</h3>
                    <p className="text-sm text-slate-500 mb-6 font-medium">Introduce el código de seguridad para continuar.</p>
                    <Input 
                        label="Código de Acceso" 
                        type="password" 
                        placeholder="*****"
                        maxLength={5}
                        className="text-center tracking-[0.5em] text-lg"
                        value={accessCodeInput} 
                        onChange={e => setAccessCodeInput(e.target.value.replace(/\D/g, ''))} 
                        onKeyPress={e => e.key === 'Enter' && handleAccessCodeSubmit()}
                    />
                    <Button className="w-full mt-4 py-4 text-lg" onClick={handleAccessCodeSubmit}>Verificar</Button>
                </Card>
             )}

             {authStep === 'EMAIL' && (
               <Card className="mt-12 animate-in zoom-in-95 duration-500 shadow-2xl border-white/80 bg-white/90">
                 <h3 className="text-3xl font-bold text-blue-900 mb-6">Identificación</h3>
                 <p className="text-base text-slate-500 mb-8 font-medium">Introduce tu correo electrónico para identificarte o registrarte.</p>
                 <Input 
