                   type="email" 
                   value={emailInput} 
                   onChange={e => setEmailInput(e.target.value)} 
                   placeholder="ejemplo@correo.com"
                   onKeyPress={e => e.key === 'Enter' && handleEmailSubmit()}
                 />
                 <Button className="w-full mt-6 py-4 text-lg" onClick={handleEmailSubmit}>Continuar</Button>
               </Card>
             )}

             {authStep === 'LOGIN_PIN' && (
               <Card className="mt-12 animate-in slide-in-from-right-8 duration-500 shadow-2xl bg-white/90">
                 <div className="flex justify-between items-center mb-8">
                   <button onClick={() => setAuthStep('EMAIL')} className="text-sm text-blue-600 font-bold hover:underline"><i className="fas fa-arrow-left"></i> Cambiar usuario</button>
                   <div className="text-xs font-black bg-blue-50 text-blue-700 px-3 py-1.5 rounded-full">{emailInput}</div>
                 </div>
                 <h3 className="text-2xl font-bold text-blue-900 mb-2">Introduce tu PIN</h3>
                 <p className="text-sm text-slate-400 mb-8 font-medium">Clave de acceso de 4 a 6 dígitos.</p>

                 <Input 
                   label="PIN de Acceso" 
                   type="password" 
                   maxLength={6}
                   placeholder="****"
                   value={pinInput} 
                   onChange={e => setPinInput(e.target.value.replace(/\D/g, ''))} 
                   onKeyPress={e => e.key === 'Enter' && handlePinLogin()}
                 />

                 <Button className="w-full mt-4 py-4 text-lg" onClick={handlePinLogin}>Entrar</Button>

                 {emailInput !== MASTER_USER.email && (
                   <button 
                     onClick={() => { setRecoveryAnswer(''); setAuthStep('RECOVERY'); }} 
