                      <p className="text-base font-bold text-blue-900">{emailInput}</p>
                    </div>

                    <Input label="Tu Nombre (Visible en Dashboard)" value={regForm.nombre} onChange={e => setRegForm({...regForm, nombre: e.target.value})} placeholder="Ej: Dr. García" />

                    <div className="grid grid-cols-2 gap-6">
                      <Input label="Crear PIN (4-6)" type="password" maxLength={6} value={regForm.pin} onChange={e => setRegForm({...regForm, pin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                      <Input label="Confirmar PIN" type="password" maxLength={6} value={regForm.confirmPin} onChange={e => setRegForm({...regForm, confirmPin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                    </div>

                    <div className="pt-6 border-t border-slate-100">
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Recuperación de Cuenta</p>
                      <Input label="Pregunta de Seguridad" value={regForm.question} onChange={e => setRegForm({...regForm, question: e.target.value})} placeholder="Ej: ¿Nombre de mi primera mascota?" />
                      <Input label="Respuesta" value={regForm.answer} onChange={e => setRegForm({...regForm, answer: e.target.value})} placeholder="Tu respuesta secreta" />
                    </div>

                    <Button className="w-full py-5 mt-4 text-lg" onClick={handleRegister}>Registrar y Acceder</Button>
                  </div>
               </Card>
             )}

            {authStep === 'RECOVERY' && currentUserData && (
               <Card className="mt-12 animate-in slide-in-from-right-8 duration-500 shadow-2xl">
                 <div className="flex justify-start mb-6">
                   <button onClick={() => setAuthStep('LOGIN_PIN')} className="text-sm text-blue-500 font-bold hover:underline"><i className="fas fa-arrow-left"></i> Volver</button>
                 </div>
                 <h3 className="text-2xl font-bold text-blue-900 mb-6">Recuperar Acceso</h3>
                 <div className="bg-amber-50 p-5 rounded-2xl border border-amber-100 mb-8 text-left">
                    <p className="text-xs font-black text-amber-600 uppercase mb-2">Pregunta de Seguridad:</p>
                    <p className="text-base font-bold text-amber-900">{currentUserData.securityQuestion}</p>
                 </div>

                 <Input 
                   label="Tu Respuesta" 
                   value={recoveryAnswer} 
                   onChange={e => setRecoveryAnswer(e.target.value)} 
                   placeholder="Escribe tu respuesta..."
                 />

                 <Button className="w-full mt-6 py-4 text-lg" onClick={handleRecoveryCheck}>Verificar</Button>
               </Card>
             )}

             {authStep === 'RESET_PIN' && (
               <Card className="mt-12 animate-in slide-in-from-right-8 duration-500 shadow-2xl">
                 <h3 className="text-2xl font-bold text-blue-900 mb-6">Establecer Nuevo PIN</h3>
                 <Input label="Nuevo PIN (4-6 dígitos)" type="password" maxLength={6} value={regForm.pin} onChange={e => setRegForm({...regForm, pin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                 <Input label="Confirmar Nuevo PIN" type="password" maxLength={6} value={regForm.confirmPin} onChange={e => setRegForm({...regForm, confirmPin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                 <Button className="w-full mt-6 py-4 text-lg" onClick={handleResetPin}>Guardar Nuevo PIN</Button>
               </Card>
             )}

           </div>
        </div>
      )}

      {view === 'COORDINATOR' && coordinator && (
        <CoordinatorDashboard 
          profile={coordinator} 
          onLogout={handleLogout} 
          onEnterEditMode={enterEditMode}
        />
      )}

      {view === 'PATIENT_SESSION' && (
        <PatientInterface 
          patientData={patientData} 
          isEditorMode={isEditorMode}
          onExitEditor={() => {
            setIsEditorMode(false);
            setView('COORDINATOR');
            window.location.hash = '#/coordinator';
          }}
        />
      )}

      {view === 'CONCLUSION_VIEW' && conclusionPatientId && (
          <ConclusionPatientView patientId={conclusionPatientId} />
      )}

      <Toast message={toast.msg} visible={toast.show} onHide={() => setToast({ ...toast, show: false })} />
    </div>
  );
};

