                </div>

                <div className="p-6 border-t bg-slate-50 flex items-center gap-4">
                    {isEditingDetails ? (
                        <>
                             <Button onClick={handleSaveDetails} className="bg-green-600 hover:bg-green-700 shadow-green-200">
                                <i className="fas fa-save mr-2"></i> Guardar Cambios
