            <Card className="shadow-xl bg-white/95 border-blue-50">
              <div className="flex items-center justify-between mb-10 border-b border-slate-100 pb-6">
                <h2 className="text-3xl font-bold text-blue-900">Preparar Nueva Sesión</h2>
                <div className="text-xs font-black text-teal-600 bg-teal-50 px-4 py-2 rounded-full uppercase tracking-widest">
                  Envío Directo
                </div>
              </div>

              <div className="space-y-8">
