interface ConclusionPatientViewProps {
  patientId: string;
}

export const ConclusionPatientView: React.FC<ConclusionPatientViewProps> = ({ patientId }) => {
  const [patient, setPatient] = useState<PatientData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [expired, setExpired] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Cargar pacientes
    const loadData = () => {
        try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                const registry: PatientData[] = JSON.parse(saved);
                const found = registry.find(p => p.id === patientId);

                if (found) {
                    const views = found.conclusionViews || 0;

                    if (views >= 2) {
                        setExpired(true);
                        setLoading(false);
                    } else {
                        // Incrementar contador y marcar como FINALIZADO
                        const updated = registry.map(p => {
                            if (p.id === patientId) {
                                return { 
                                    ...p, 
                                    conclusionViews: (p.conclusionViews || 0) + 1,
                                    status: 'finalized' as const, // Cambio automático a Finalizado
                                    dateConclusionViewed: Date.now()
                                };
                            }
                            return p;
                        });
                        localStorage.setItem('radar_patients', JSON.stringify(updated));
                        setPatient(found);
                        setLoading(false);
                    }
                } else {
                    setError("No se ha encontrado el registro.");
                    setLoading(false);
                }
            } else {
                 setError("Base de datos no disponible.");
                 setLoading(false);
            }
        } catch (e) {
            setError("Error al cargar la conclusión.");
            setLoading(false);
        }
