  };

  const handleSendConclusionWhatsApp = () => {
    if (!selectedPatientConclusion || !selectedPatientConclusion.telefono) return alert("Falta teléfono.");
    const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
    window.open(`https://wa.me/${selectedPatientConclusion.telefono.replace(/\D/g, '')}?text=${encodeURIComponent(body)}`, '_blank');
    markAsConcluded(selectedPatientConclusion.id);
    triggerToast("WhatsApp abierto");
  };

  const handlePrintPatientFile = () => { /* Lógica de impresión existente... */ };
  const handlePrintPatientResults = () => { /* Lógica de impresión existente... */ };
  const handleDownloadPDF = async () => { /* Lógica PDF existente... */ };

  const filteredRegistry = registry.filter(p => {
      const matchesSearch = searchTerm === '' || p.nombre.toLowerCase().includes(searchTerm.toLowerCase()) || p.email.toLowerCase().includes(searchTerm.toLowerCase());
