                    <textarea className="w-full h-[32rem] p-4 rounded-xl border-2 border-slate-200 focus:border-purple-500 outline-none text-base leading-relaxed resize-none bg-white text-slate-700" value={editingConclusion} onChange={(e) => setEditingConclusion(e.target.value)} />
