      <div className="max-w-6xl mx-auto py-10 px-6 md:px-8 pb-32">
        <div className="flex justify-between items-center mb-10"><Logo /><Button onClick={onLogout}>Cerrar Sesión</Button></div>
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          <div className="lg:col-span-4 space-y-8">
            <Card className="border-teal-100 border-2 shadow-xl bg-white/95">
              <h2 className="text-2xl font-bold mb-6 text-blue-900 border-b pb-4">Especialista</h2>
              <div className="flex items-center gap-5 p-5 bg-teal-50 to-white rounded-2xl border">
                <div className="w-16 h-16 bg-blue-900 text-white rounded-2xl flex items-center justify-center text-2xl font-black">{profile.nombre.charAt(0)}</div>
                <div><p className="font-bold text-lg text-slate-800">{profile.nombre}</p><p className="text-sm text-teal-600 font-bold">{profile.email}</p></div>
