                          <span className="text-[10px] font-black uppercase bg-slate-100 px-2 py-1 rounded">{statusLabels[p.status]}</span>
                      </div>
                      {(p.status === 'completed' || p.status === 'concluded' || p.status === 'finalized') && (
                          <div className="flex gap-2 pt-2 border-t">
                              <button onClick={() => openResultsModal(p)} className="flex-1 py-2 text-xs font-bold bg-blue-50 text-blue-600 rounded-lg">Ver</button>
                              <button onClick={() => openConclusionModal(p)} className="flex-1 py-2 text-xs font-bold bg-purple-50 text-purple-600 rounded-lg">Conclusión</button>
                          </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            </Card>
          </div>

          <div className="lg:col-span-8">
            <Card className="shadow-xl bg-white/95 border-blue-50">
              <h2 className="text-3xl font-bold text-blue-900 mb-8 border-b pb-6">Preparar Nueva Sesión</h2>
              <div className="space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2">
                  <Input label="Nombre completo" value={patient.nombre} onChange={e => setPatient({ ...patient, nombre: e.target.value })} />
                  <Input label="Email del paciente" value={patient.email} onChange={e => setPatient({ ...patient, email: e.target.value })} />
                </div>
                <div className="mb-4">
                  <label className="block text-[11px] font-black uppercase text-slate-500 mb-2">WhatsApp</label>
                  <div className="flex gap-2">
                      <input className="w-20 px-4 py-4 rounded-2xl border-2 border-slate-100 text-center" value={phonePrefix} onChange={e => setPhonePrefix(e.target.value)} />
                      <input className="flex-1 px-5 py-4 rounded-2xl border-2 border-slate-100" placeholder="600123456" value={phoneBody} onChange={e => setPhoneBody(e.target.value)} />
                  </div>
                </div>
                <div className="bg-slate-50 p-6 rounded-3xl border">
                  <p className="text-xs font-black text-slate-400 uppercase mb-6">Vías de Notificación</p>
                  <div className="flex flex-wrap gap-6">
                    <label className="flex items-center gap-3 cursor-pointer"><input type="checkbox" checked={sendMethods.email} onChange={e => setSendMethods({...sendMethods, email: e.target.checked})} /><span className="text-sm font-bold">Gmail</span></label>
                    <label className="flex items-center gap-3 cursor-pointer"><input type="checkbox" checked={sendMethods.whatsapp} onChange={e => setSendMethods({...sendMethods, whatsapp: e.target.checked})} /><span className="text-sm font-bold">Whatsapp</span></label>
                  </div>
                </div>
                <Button className="w-full py-5 text-xl font-bold" variant="secondary" onClick={() => handleGenerateAndSend(false)}><i className="fas fa-paper-plane mr-3"></i> Generar y Notificar</Button>
              </div>
            </Card>
          </div>
        </div>
      </div>
      <Toast message={toastMessage} visible={showToast} onHide={() => setShowToast(false)} />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { DataService } from '../services/dataService'; 
import { PatientData, Voice, Question, GlobalConfig, DualAudio } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_CONFIG: GlobalConfig = {
  welcomeText: "Hola soy el Radar que ahora te va a guiar...",
  welcomeAudio: {},
  nameQuestionText: "¿Cómo te llamas?...",
  nameQuestionAudio: {},
  startText: "Bienvenido {{nombre}}...",
  startAudio: {},
  finishText: "Tus respuestas y la valoración están listas...",
  finishAudio: {},
  afterSendText: "Envio realizado {{nombre}}...",
  afterSendAudio: {},
  defaultVoiceMode: Voice.FEMALE
};

const FALLBACK_TEXTURE = "https://images.unsplash.com/photo-1516550893923-42d28e5677af?q=80&w=2070&auto=format&fit=crop";
const BACKGROUNDS = { intro: 'assets/fondo1.webp', verification: 'assets/fondo2.webp', general: 'assets/fondo3.webp' };
const AUDIO_START_DELAY = 800;

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-4`}>
    <div className={`max-w-[85%] px-6 py-4 rounded-2xl text-base font-medium leading-relaxed shadow-md border backdrop-blur-sm ${
      msg.sender === 'ia' ? (isDarkMode ? 'bg-[#1e293b]/90 text-blue-100 border-white/10' : 'bg-white/95 text-slate-800 border-blue-100') + ' rounded-tl-none' : (isDarkMode ? 'bg-blue-600/90 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-500') + ' rounded-tr-none'
    }`}>{msg.text}</div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);
  const [globalConfig, setGlobalConfig] = useState<GlobalConfig>(() => {
    try { const saved = localStorage.getItem('radar_global_config'); return saved ? JSON.parse(saved) : DEFAULT_CONFIG; } catch(e) { return DEFAULT_CONFIG; }
  });

  const [questions, setQuestions] = useState<Question[]>(() => {
    try {
        const saved = localStorage.getItem('radar_custom_questions');
        const parsed = saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
        return Array.isArray(parsed) && parsed.length > 0 ? parsed : INITIAL_QUESTIONS;
    } catch(e) { return INITIAL_QUESTIONS; }
  });

  useEffect(() => {
    const fetchData = async () => {
        // Forzamos la carga de preguntas más recientes de todas las fuentes posibles
        const remoteQuestions = await DataService.getQuestions();
        if (remoteQuestions && remoteQuestions.length > 0) {
            setQuestions(remoteQuestions);
            // También actualizamos el localStorage para consistencia futura
            localStorage.setItem('radar_custom_questions', JSON.stringify(remoteQuestions));
        }
        const remoteConfig = await DataService.getGlobalConfig(DEFAULT_CONFIG);
        setGlobalConfig(remoteConfig);
    };
    fetchData();
  }, []);

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish' | 'locked'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(globalConfig.defaultVoiceMode);
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [hasSentResults, setHasSentResults] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [isInteractionLocked, setIsInteractionLocked] = useState(false);
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isEditingGlobal, setIsEditingGlobal] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [verificationAttempts, setVerificationAttempts] = useState(0);
  const currentAudioRef = useRef<HTMLAudioElement | null>(null);
  const speechTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!isEditorMode && currentPatientData.id && (currentPatientData.status === 'pending' || currentPatientData.status === 'sent')) {
        try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                let registry: PatientData[] = JSON.parse(saved);
                registry = registry.map(p => p.id === currentPatientData.id ? { ...p, status: 'viewed' } : p);
                localStorage.setItem('radar_patients', JSON.stringify(registry));
                setCurrentPatientData(prev => ({ ...prev, status: 'viewed' }));
            }
        } catch(e) {}
    }
  }, [currentPatientData.id, isEditorMode]);

  const processText = (text: string) => {
    if (!text) return "";
    const name = currentPatientData.nombre?.split(' ')[0] || 'amigo/a';
    const isFemale = (currentPatientData.sexo || '').toLowerCase().includes('mujer');
    return text.replace(/{{nombre}}/gi, name).replace(/@/g, isFemale ? 'a' : 'o');
  };

  const playOrSpeak = async (text: string, audioData?: DualAudio): Promise<void> => {
    stopAudio();
    if (voice === Voice.NONE) return new Promise(resolve => setTimeout(resolve, 1500));
    setIsSpeaking(true);
    return new Promise((resolve) => {
      speechTimeoutRef.current = setTimeout(() => {
          const customUrl = voice === Voice.MALE ? audioData?.male : audioData?.female;
          if (customUrl) {
            const audio = new Audio(customUrl);
            currentAudioRef.current = audio;
            audio.onended = () => { setIsSpeaking(false); resolve(); };
            audio.play().catch(() => speakNative(text, resolve));
            return;
          }
          speakNative(text, resolve);
      }, AUDIO_START_DELAY);
    });
  };

  const speakNative = (text: string, onEnd: () => void) => {
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'es-ES';
    utterance.onend = () => { setIsSpeaking(false); onEnd(); };
    window.speechSynthesis.speak(utterance);
  };

  const stopAudio = () => {
    if (speechTimeoutRef.current) clearTimeout(speechTimeoutRef.current);
    window.speechSynthesis.cancel();
    if (currentAudioRef.current) { currentAudioRef.current.pause(); currentAudioRef.current = null; }
    setIsSpeaking(false);
  };

  const startSession = async () => {
    setStep('verification');
    const welcome = processText(globalConfig.welcomeText);
    addMessage(welcome, 'ia');
    await playOrSpeak(welcome, globalConfig.welcomeAudio);
    const nameQ = processText(globalConfig.nameQuestionText);
    addMessage(nameQ, 'ia');
    await playOrSpeak(nameQ, globalConfig.nameQuestionAudio);
  };

  const handleVerification = async (nameInput: string) => {
    stopAudio();
    addMessage(nameInput, 'user');
    const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
    const inputLower = nameInput.trim().toLowerCase();
    const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

    if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
        setCurrentPatientData({ ...currentPatientData, nombre: nameInput });
        proceedToQuestionnaire();
    } else {
        const mismatchMsg = `El nombre no coincide. Por favor, escribe tu nombre completo.`;
        addMessage(mismatchMsg, 'ia');
        await playOrSpeak(mismatchMsg);
    }
  };

  const proceedToQuestionnaire = async () => {
    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    if (!q) { setStep('finish'); return; }
    setIsInteractionLocked(true);
    setVisibleOptions([]);
    await playOrSpeak(processText(q.speechScript || q.scenario), q.audio);
    if (!q.isScale) {
        for (const opt of q.options) {
            setVisibleOptions(prev => [...prev, opt.key]);
            await playOrSpeak(`Opción ${opt.key}... ${processText(opt.text)}`, opt.audio);
        }
    }
    setIsInteractionLocked(false);
  };

  const handleAnswer = (key: string) => {
    if (isInteractionLocked) return;
    stopAudio();
    setAnswers(prev => ({ ...prev, [questions[currentQuestionIndex].id]: key }));
    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => setTranscript(prev => [...prev, { text, sender }]);

  const saveQuestionChanges = () => {
    if (!editingQuestion) return;
    const updated = questions.some(q => q.id === editingQuestion.id) ? questions.map(q => q.id === editingQuestion.id ? editingQuestion : q) : [...questions, editingQuestion];
    setQuestions(updated);
    localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    setEditingQuestion(null);
  };

  const handleSendResults = async () => {
    const updatedData = { ...currentPatientData, dateAnswered: Date.now() };
    try {
        const saved = localStorage.getItem('radar_patients');
        if (saved && currentPatientData.id) {
            let registry: PatientData[] = JSON.parse(saved);
            registry = registry.map(p => p.id === currentPatientData.id ? { ...p, status: 'completed', dateAnswered: Date.now() } : p);
            localStorage.setItem('radar_patients', JSON.stringify(registry));
        }
    } catch(e) {}
    setHasSentResults(true);
    const afterMsg = processText(globalConfig.afterSendText);
    addMessage(afterMsg, 'ia');
    await playOrSpeak(afterMsg, globalConfig.afterSendAudio);
    // Disparar envío por email al coordinador
    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    window.location.href = `mailto:${email}?subject=Resultados: ${currentPatientData.nombre}&body=Informe listo...`;
  };

  return (
    <div className={`min-h-screen flex flex-col relative overflow-hidden ${isDarkMode ? "bg-[#0f172a]" : "bg-[#faf9f6]"}`}>
      <div className="fixed inset-0 z-0 bg-cover bg-center" style={{ backgroundImage: `url('${BACKGROUNDS.general}')` }}>
        <div className={`absolute inset-0 ${isDarkMode ? 'bg-[#0f172a]/60' : 'bg-white/40'}`}></div>
      </div>

      <header className="backdrop-blur-md border-b p-4 sticky top-0 z-50">
        <div className="max-w-xl mx-auto flex justify-between items-center">
          <Logo size="sm" isDark={isDarkMode} />
          <Button variant="outline" onClick={() => setShowExitConfirm(true)}><i className="fas fa-times"></i></Button>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-8 pb-32 relative z-10">
        {step === 'intro' ? (
          <div className="min-h-[60vh] flex flex-col items-center justify-center">
            <Button onClick={startSession} className="scale-125">Empezar Cuestionario</Button>
          </div>
        ) : step === 'questionnaire' && questions[currentQuestionIndex] ? (
          <div className="space-y-6">
            <ProgressBar current={currentQuestionIndex + 1} total={questions.length} />
            <Card className="p-10">
                <h2 className="text-2xl md:text-3xl font-bold">{processText(questions[currentQuestionIndex].scenario)}</h2>
                {isEditorMode && <Button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="mt-4">Editar</Button>}
            </Card>
            <div className="space-y-4">
                {questions[currentQuestionIndex].options.map(opt => (
                    (visibleOptions.includes(opt.key) || isEditorMode) && (
                        <button key={opt.key} onClick={() => handleAnswer(opt.key)} className="w-full text-left p-6 rounded-2xl border-2 bg-white/80 hover:border-blue-400 flex gap-4">
                            <span className="w-10 h-10 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-black">{opt.key.toUpperCase()}</span>
                            <span className="font-bold text-lg">{processText(opt.text)}</span>
                        </button>
                    )
                ))}
            </div>
          </div>
        ) : step === 'finish' ? (
            <Card className="text-center py-16">
                <h2 className="text-3xl font-bold mb-6">¡Gracias!</h2>
                <Button onClick={handleSendResults}>Enviar Resultados</Button>
            </Card>
        ) : null}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className="fixed bottom-0 left-0 right-0 p-4 border-t z-50 bg-white/70 backdrop-blur-md">
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full mb-4">
                <input className="flex-1 px-6 py-4 rounded-2xl border-2" placeholder="Tu nombre..." value={inputValue} onChange={e => setInputValue(e.target.value)} />
                <Button onClick={() => handleVerification(inputValue)}>Enviar</Button>
              </div>
            )}
            <button className="w-16 h-16 bg-blue-600 text-white rounded-full"><i className="fas fa-microphone text-2xl"></i></button>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4">
            <Card className="max-w-4xl w-full max-h-[90vh] overflow-y-auto">
                <h3 className="text-xl font-bold mb-4">Editar Pregunta</h3>
                <textarea className="w-full p-4 border rounded mb-4" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                <Button onClick={saveQuestionChanges}>Guardar</Button>
            </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, Input } from './UI';
import { PatientData } from '../types';

interface ConclusionPatientViewProps {
  patientId: string;
}

export const ConclusionPatientView: React.FC<ConclusionPatientViewProps> = ({ patientId }) => {
  const [patient, setPatient] = useState<PatientData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [expired, setExpired] = useState(false);
  const [isPinVerified, setIsPinVerified] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [pinError, setPinError] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const loadData = () => {
        try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                const registry: PatientData[] = JSON.parse(saved);
                const found = registry.find(p => p.id === patientId);

                if (found) {
                    if ((found.conclusionViews || 0) >= 2) {
                        setExpired(true);
                    } else {
                        setPatient(found);
                    }
                } else setError("No se ha encontrado el registro.");
            } else setError("Base de datos no disponible.");
        } catch (e) { setError("Error al cargar la conclusión."); }
        setLoading(false);
    };
    loadData();
  }, [patientId]);

  const verifyPin = () => {
      if (patient && pinInput === patient.accessPin) {
          setIsPinVerified(true);
          // Incrementar visualizaciones
          try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                const registry: PatientData[] = JSON.parse(saved);
                const updated = registry.map(p => p.id === patientId ? { ...p, conclusionViews: (p.conclusionViews || 0) + 1, status: 'finalized' as const, dateConclusionViewed: Date.now() } : p);
                localStorage.setItem('radar_patients', JSON.stringify(updated));
            }
          } catch(e) {}
      } else {
          setPinError(true);
          setTimeout(() => setPinError(false), 2000);
      }
  };

  const handleBooking = () => window.location.href = "https://example.com/reserva"; 
  const handleLearnMore = () => window.location.href = "https://example.com/terapias";
  const handlePlayAudio = () => audioRef.current?.play();

  if (loading) return <div className="min-h-screen flex items-center justify-center"><div className="animate-spin w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full"></div></div>;

  if (expired) return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-[#faf9f6]">
       <Card className="text-center max-w-lg w-full py-12 px-8">
           <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl"><i className="fas fa-lock"></i></div>
           <h2 className="text-2xl font-bold mb-4">Enlace Caducado</h2>
           <p className="text-slate-500 mb-8">Este enlace ha alcanzado el límite de visualizaciones por seguridad.</p>
           <Button onClick={handleBooking} className="w-full py-4 text-lg bg-blue-600">Reserva Ahora</Button>
       </Card>
    </div>
  );

  if (!isPinVerified && patient) {
      return (
        <div className="min-h-screen flex items-center justify-center p-4 relative">
            <div className="absolute inset-0 z-0 bg-cover bg-center opacity-60" style={{ backgroundImage: "url('assets/fondoconclusion.webp')" }}></div>
            <Card className="max-w-md w-full p-10 relative z-10 text-center shadow-2xl border-white/50 backdrop-blur-md">
                <Logo />
                <div className="mt-8 mb-6">
                    <h3 className="text-xl font-bold text-blue-900 mb-2">Acceso Protegido</h3>
                    <p className="text-sm text-slate-500">Introduce tu clave de 4 dígitos para ver tus resultados.</p>
                </div>
                <div className="mb-8">
                    <input 
                        type="password" 
                        maxLength={4} 
                        className={`w-full text-center text-3xl tracking-[1em] p-4 rounded-2xl border-2 outline-none transition-all ${pinError ? 'border-red-500 bg-red-50 animate-shake' : 'border-blue-100 focus:border-blue-500'}`}
                        placeholder="****"
                        value={pinInput}
                        onChange={e => setPinInput(e.target.value.replace(/\D/g, ''))}
                        onKeyPress={e => e.key === 'Enter' && pinInput.length === 4 && verifyPin()}
                    />
                    {pinError && <p className="text-red-500 text-xs font-bold mt-2">Clave incorrecta</p>}
                </div>
                <Button onClick={verifyPin} disabled={pinInput.length < 4} className="w-full py-4 text-lg">Entrar al Informe</Button>
            </Card>
        </div>
      );
  }

  if (error || !patient) return <div className="min-h-screen flex items-center justify-center"><h2>{error || "Error inesperado"}</h2></div>;

  return (
    <div className="min-h-screen bg-[#faf9f6] relative font-sans">
        <div className="absolute inset-0 z-0 bg-cover bg-center opacity-80" style={{ backgroundImage: "url('assets/fondoconclusion.webp')" }}>
            <div className="absolute inset-0 bg-white/40 backdrop-blur-sm"></div>
        </div>

        {patient.audioConclusion && <audio ref={audioRef} src={patient.audioConclusion} className="hidden" />}

        <div className="max-w-4xl mx-auto relative z-10 p-4 md:p-8">
            <div className="mb-10 text-center"><Logo /></div>

            <Card className="mb-12 border-none shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-700">
                <div className="bg-gradient-to-r from-blue-900 to-indigo-900 p-8 md:p-14 text-white relative">
                    <div className="relative z-10">
                        <h2 className="text-3xl md:text-5xl font-friendly font-bold mb-4">Análisis Terapéutico</h2>
                        <p className="text-blue-100 text-lg">Informe para: <span className="font-bold text-white ml-2">{patient.nombre}</span></p>
                    </div>
                    {patient.audioConclusion && (
                        <button onClick={handlePlayAudio} className="absolute top-8 right-8 w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-lg text-blue-600 hover:scale-110 transition-all"><i className="fas fa-play text-2xl ml-1"></i></button>
                    )}
                </div>

                <div className="p-8 md:p-14 bg-white/95">
                    <div className="prose prose-lg max-w-none text-slate-700 leading-loose whitespace-pre-line text-justify font-medium">
                        {patient.finalConclusion || patient.conversationSummary || "Tu informe está siendo procesado."}
                    </div>
                </div>

                <div className="bg-blue-50/80 p-6 flex items-center justify-center gap-3 text-blue-900 text-sm font-bold border-t backdrop-blur-md">
                    <i className="fas fa-shield-alt text-blue-500"></i>
                    <span>Acceso de seguridad mediante PIN personal.</span>
                </div>
            </Card>

            <div className="text-center space-y-10 mb-24">
                <div className="space-y-4">
                    <h3 className="text-3xl md:text-4xl font-bold text-slate-800">Es el momento de tomar el control</h3>
                </div>
                <div className="flex flex-col md:flex-row items-center justify-center gap-6 px-4">
                    <button onClick={handleBooking} className="w-full md:w-auto px-10 py-6 text-xl font-black rounded-3xl bg-gradient-to-r from-blue-600 to-indigo-700 text-white shadow-2xl hover:scale-105 transition-all">Reservar terapia</button>
                    <button onClick={handleLearnMore} className="w-full md:w-auto px-10 py-6 text-lg font-bold rounded-3xl bg-white text-indigo-700 border-2 border-indigo-100 shadow-xl">Conocer más sobre las terapias</button>
                </div>
            </div>
        </div>
    </div>
  );
};

