import { QUESTIONS } from '../constants';
import { DataService } from '../services/dataService';

interface DashboardProps {
  profile: CoordinatorProfile;
  onLogout: () => void;
  onEnterEditMode: () => void;
}

const safeBtoa = (str: string) => {
  return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
      function toSolidBytes(match, p1) {
          return String.fromCharCode(parseInt(p1, 16));
  }));
};

const formatDate = (timestamp?: number) => {
    if (!timestamp) return 'Pendiente';
    return new Date(timestamp).toLocaleDateString() + ' ' + new Date(timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
};

const INTERNAL_CLINICAL_EXAMPLE = `INFORME DE VALORACIÓN INICIAL Y GUÍA TERAPÉUTICA AVANZADA...`;
const EXTERNAL_PATIENT_EXAMPLE = `Hola Martín, he analizado detenidamente tus respuestas...`;

export const CoordinatorDashboard: React.FC<DashboardProps> = ({ profile, onLogout, onEnterEditMode }) => {
  const [patient, setPatient] = useState<Partial<PatientData>>({
    nombre: '', edad: '', sexo: '', observaciones: '', telefono: '', email: ''
  });

  const [phonePrefix, setPhonePrefix] = useState('+34');
  const [phoneBody, setPhoneBody] = useState('');
  const [sendMethods, setSendMethods] = useState({ email: true, whatsapp: false, sms: false });
  const [linkGenerated, setLinkGenerated] = useState<string | null>(null);
  const [registry, setRegistry] = useState<PatientData[]>([]);
  const [toastMessage, setToastMessage] = useState('');
  const [showToast, setShowToast] = useState(false);
  const [dateStart, setDateStart] = useState('');
  const [dateEnd, setDateEnd] = useState('');
  const [selectedPatientResults, setSelectedPatientResults] = useState<PatientData | null>(null);
  const [selectedPatientConclusion, setSelectedPatientConclusion] = useState<PatientData | null>(null);
  const [selectedPatientDetails, setSelectedPatientDetails] = useState<PatientData | null>(null); 
  const [isEditingDetails, setIsEditingDetails] = useState(false);
  const [tempPatientDetails, setTempPatientDetails] = useState<PatientData | null>(null);
  const [editingConclusion, setEditingConclusion] = useState('');
  const [editingAudio, setEditingAudio] = useState<string | undefined>(undefined);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');

  const statusLabels: Record<string, string> = {
      'all': 'Todos', 'pending': 'Pendiente', 'sent': 'Enviado', 'viewed': 'Visto', 'completed': 'Hecho', 'concluded': 'Concluido', 'finalized': 'Finalizado'
  };

  useEffect(() => {
    try {
        const saved = localStorage.getItem('radar_patients');
        if (saved) setRegistry(JSON.parse(saved));
    } catch (e) { console.error("Error cargando registros", e); }
  }, []);

  const triggerToast = (msg: string) => {
    setToastMessage(msg);
    setShowToast(true);
  };

  const saveRegistry = (newRegistry: PatientData[]) => {
    setRegistry(newRegistry);
    localStorage.setItem('radar_patients', JSON.stringify(newRegistry));
  };

  const deleteRecord = (id: string) => {
    if(!confirm("¿Estás seguro?")) return;
    const updated = registry.filter(r => r.id !== id);
    saveRegistry(updated);
    triggerToast("Registro eliminado");
  };

  const toggleStatus = (id: string) => {
    const updated = registry.map(r => r.id === id && r.status === 'pending' ? { ...r, status: 'sent' as const } : r);
    saveRegistry(updated);
    triggerToast("Estado actualizado");
  };

  const handleGenerateAndSend = (isResend: boolean = false) => {
    if (!patient.nombre || !patient.email) return alert("Nombre y Email requeridos.");

    const fullPhone = phoneBody ? `${phonePrefix}${phoneBody}`.trim() : '';
    const now = Date.now();

    // Generación de PIN de 4 dígitos aleatorio
    const accessPin = Math.floor(1000 + Math.random() * 9000).toString();

    const payload = { 
      nombre: patient.nombre, email: patient.email, telefono: fullPhone, 
      edad: patient.edad, sexo: patient.sexo, coordinatorEmail: profile.email, timestamp: now
    };

    try {
        const idEncoded = safeBtoa(JSON.stringify(payload));
        // Dominio absoluto solicitado
        const baseUrl = "https://el-cuestionario-espejo.vercel.app/";
        const url = `${baseUrl}#/session?p=${idEncoded}`;

        setLinkGenerated(url);

        const newRecord: PatientData = { 
          ...patient as PatientData, 
          telefono: fullPhone, id: idEncoded, status: 'pending', dateSent: now, accessPin 
        };

        saveRegistry([...registry, newRecord]);

        let subject = "Tu enlace para el Cuestionario Espejo";
        let body = `Hola ${patient.nombre.split(' ')[0]},\n\nAquí tienes tu enlace directo para realizar el Cuestionario Espejo:\n${url}\n\nIMPORTANTE: Tu clave numérica de acceso a los resultados finales es: ${accessPin}. No la pierdas, ya que la necesitarás más adelante para ver tu conclusión.\n\nGracias.`;

        if (isResend) {
            subject = "Actualización: Cuestionario Espejo";
            body = `Hola ${patient.nombre.split(' ')[0]},\n\nHemos actualizado tu cuestionario. Puedes acceder aquí:\n${url}\n\nRecuerda que tu clave de acceso a resultados es: ${accessPin}\n\nUn saludo.`;
        }

        if (sendMethods.whatsapp && fullPhone) {
          window.open(`https://wa.me/${fullPhone.replace(/\D/g, '')}?text=${encodeURIComponent(body)}`, '_blank');
        }
        if (sendMethods.email) {
          window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(patient.email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`, '_blank');
        }
        triggerToast("Enlace generado y enviado con PIN de seguridad");
    } catch (error) { alert("Error al generar el enlace."); }
  };

  const handleResendFromDetails = () => {
      if (!selectedPatientDetails) return;
      const p = selectedPatientDetails;
      setPatient({ nombre: p.nombre, email: p.email, edad: p.edad, sexo: p.sexo, telefono: p.telefono, observaciones: p.observaciones });
      setSelectedPatientDetails(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      setTimeout(() => handleGenerateAndSend(true), 500);
  };

  const openResultsModal = (p: PatientData) => setSelectedPatientResults(p);
  const openConclusionModal = (p: PatientData) => {
    setSelectedPatientConclusion(p);
    setEditingConclusion(p.finalConclusion || EXTERNAL_PATIENT_EXAMPLE);
    setEditingAudio(p.audioConclusion);
  };

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file && file.size <= 1048576) {
          const reader = new FileReader();
          reader.onload = (ev) => setEditingAudio(ev.target?.result as string);
          reader.readAsDataURL(file);
      } else if (file) alert("Audio demasiado grande (Max 1MB).");
  };

  const handleSaveConclusion = () => {
    if (!selectedPatientConclusion) return;
    const updated = registry.map(r => r.id === selectedPatientConclusion.id ? { ...r, finalConclusion: editingConclusion, audioConclusion: editingAudio } : r);
    saveRegistry(updated);
    setSelectedPatientConclusion({ ...selectedPatientConclusion, finalConclusion: editingConclusion, audioConclusion: editingAudio });
    triggerToast("Conclusión guardada");
  };

  const handleEditDetails = () => { if (selectedPatientDetails) { setTempPatientDetails(selectedPatientDetails); setIsEditingDetails(true); } };
  const handleSaveDetails = () => {
      if (!tempPatientDetails) return;
      const updated = registry.map(r => r.id === tempPatientDetails.id ? tempPatientDetails : r);
      saveRegistry(updated);
      setSelectedPatientDetails(tempPatientDetails);
      setIsEditingDetails(false);
      triggerToast("Ficha actualizada");
  };

  const getConclusionUrlAndBody = (p: PatientData) => {
    const baseUrl = "https://el-cuestionario-espejo.vercel.app/";
    const url = `${baseUrl}#/conclusion?id=${encodeURIComponent(p.id)}`;
    const body = `Hola ${p.nombre.split(' ')[0]},\n\nYa están disponibles tus resultados del Cuestionario Espejo.\n\nPuedes verlos en el siguiente enlace:\n${url}\n\nIMPORTANTE: Se te pedirá la clave numérica de 4 dígitos que se te entregó al iniciar el cuestionario.`;
    return { url, body };
  };

  const markAsConcluded = (id: string) => {
      const updated = registry.map(r => r.id === id ? { ...r, status: 'concluded' as const, dateConclusionSent: Date.now(), conclusionViews: 0 } : r);
      saveRegistry(updated);
  };

  const handleSendConclusionLink = () => {
    if (!selectedPatientConclusion) return;
    const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(selectedPatientConclusion.email)}&su=${encodeURIComponent("Resultados - Cuestionario Espejo")}&body=${encodeURIComponent(body)}`, '_blank');
    markAsConcluded(selectedPatientConclusion.id);
    triggerToast("Gmail abierto");
  };

  const handleSendConclusionWhatsApp = () => {
    if (!selectedPatientConclusion || !selectedPatientConclusion.telefono) return alert("Falta teléfono.");
    const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
    window.open(`https://wa.me/${selectedPatientConclusion.telefono.replace(/\D/g, '')}?text=${encodeURIComponent(body)}`, '_blank');
    markAsConcluded(selectedPatientConclusion.id);
    triggerToast("WhatsApp abierto");
  };

  const filteredRegistry = registry.filter(p => {
      const matchesSearch = searchTerm === '' || p.nombre.toLowerCase().includes(searchTerm.toLowerCase()) || p.email.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'all' || p.status === filterStatus;
      return matchesSearch && matchesStatus;
  });

  return (
    <div className="min-h-screen overflow-y-auto relative">
      <div className="absolute inset-0 pointer-events-none opacity-20 bg-cover bg-center -z-10" style={{backgroundImage: "url('https://images.unsplash.com/photo-1516550893923-42d28e5677af?q=80&w=2070&auto=format&fit=crop')"}}></div>

      {/* MODAL FICHA DE PACIENTE */}
      {selectedPatientDetails && (
          <div className="fixed inset-0 z-[120] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
             <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-6 border-b flex justify-between items-center bg-blue-900 text-white">
                    <h2 className="text-2xl font-bold flex items-center gap-3"><i className="fas fa-user-circle"></i> Ficha del Paciente</h2>
                    <div className="flex gap-2">
                         {!isEditingDetails && <button onClick={handleEditDetails} className="text-blue-200 hover:text-white mr-4"><i className="fas fa-edit text-xl"></i></button>}
                         <button onClick={() => setSelectedPatientDetails(null)} className="text-blue-200 hover:text-white text-2xl"><i className="fas fa-times"></i></button>
                    </div>
                </div>
                <div className="p-8 overflow-y-auto space-y-8">
                    {isEditingDetails && tempPatientDetails ? (
                         <div className="space-y-6">
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <Input label="Nombre" value={tempPatientDetails.nombre} onChange={e => setTempPatientDetails({...tempPatientDetails, nombre: e.target.value})} />
                                <Input label="Email" value={tempPatientDetails.email} onChange={e => setTempPatientDetails({...tempPatientDetails, email: e.target.value})} />
                             </div>
                             <textarea className="w-full p-3 border rounded-lg bg-slate-50 h-64 font-medium" value={tempPatientDetails.conversationSummary} onChange={e => setTempPatientDetails({...tempPatientDetails, conversationSummary: e.target.value})} />
