export const ConclusionPatientView: React.FC<ConclusionPatientViewProps> = ({ patientId }) => {
  const [patient, setPatient] = useState<PatientData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [expired, setExpired] = useState(false);
  const [isPinVerified, setIsPinVerified] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [pinError, setPinError] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const loadData = () => {
        try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                const registry: PatientData[] = JSON.parse(saved);
                const found = registry.find(p => p.id === patientId);

                if (found) {
                    if ((found.conclusionViews || 0) >= 2) {
                        setExpired(true);
                    } else {
                        setPatient(found);
                    }
                } else setError("No se ha encontrado el registro.");
            } else setError("Base de datos no disponible.");
        } catch (e) { setError("Error al cargar la conclusión."); }
        setLoading(false);
    };
    loadData();
  }, [patientId]);

  const verifyPin = () => {
      if (patient && pinInput === patient.accessPin) {
          setIsPinVerified(true);
          try {
            const saved = localStorage.getItem('radar_patients');
            if (saved) {
                const registry: PatientData[] = JSON.parse(saved);
                const updated = registry.map(p => p.id === patientId ? { ...p, conclusionViews: (p.conclusionViews || 0) + 1, status: 'finalized' as const, dateConclusionViewed: Date.now() } : p);
                localStorage.setItem('radar_patients', JSON.stringify(updated));
            }
          } catch(e) {}
      } else {
          setPinError(true);
          setTimeout(() => setPinError(false), 2000);
      }
  };

  const handleBooking = () => window.location.href = "https://example.com/reserva"; 
  const handleLearnMore = () => window.location.href = "https://example.com/terapias";
  const handlePlayAudio = () => audioRef.current?.play();

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-[#faf9f6]"><div className="animate-spin w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full"></div></div>;

  if (expired) return (
