      );
  }

  if (error || !patient) return <div className="min-h-screen flex items-center justify-center"><h2>{error || "No se ha podido cargar el informe."}</h2></div>;

  return (
    <div className="min-h-screen bg-[#faf9f6] relative font-sans overflow-x-hidden">
