  profile: CoordinatorProfile;
  onLogout: () => void;
  onEnterEditMode: () => void;
}

const safeBtoa = (str: string) => {
  return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
      function toSolidBytes(match, p1) {
          return String.fromCharCode(parseInt(p1, 16));
  }));
};

const formatDate = (timestamp?: number) => {
    if (!timestamp) return 'Pendiente';
    return new Date(timestamp).toLocaleDateString() + ' ' + new Date(timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
};

export const CoordinatorDashboard: React.FC<DashboardProps> = ({ profile, onLogout, onEnterEditMode }) => {
  const [patient, setPatient] = useState<Partial<PatientData>>({
    nombre: '', edad: '', sexo: '', observaciones: '', telefono: '', email: ''
  });

  const [phonePrefix, setPhonePrefix] = useState('+34');
  const [phoneBody, setPhoneBody] = useState('');
  const [sendMethods, setSendMethods] = useState({ email: true, whatsapp: false, sms: false });
  const [linkGenerated, setLinkGenerated] = useState<string | null>(null);
  const [registry, setRegistry] = useState<PatientData[]>([]);
  const [toastMessage, setToastMessage] = useState('');
  const [showToast, setShowToast] = useState(false);
  const [selectedPatientResults, setSelectedPatientResults] = useState<PatientData | null>(null);
  const [selectedPatientConclusion, setSelectedPatientConclusion] = useState<PatientData | null>(null);
  const [selectedPatientDetails, setSelectedPatientDetails] = useState<PatientData | null>(null); 
  const [isEditingDetails, setIsEditingDetails] = useState(false);
  const [tempPatientDetails, setTempPatientDetails] = useState<PatientData | null>(null);
  const [editingConclusion, setEditingConclusion] = useState('');
  const [editingAudio, setEditingAudio] = useState<string | undefined>(undefined);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');

  const statusLabels: Record<string, string> = {
      'all': 'Todos', 'pending': 'Pendiente', 'sent': 'Enviado', 'viewed': 'Visto', 'completed': 'Hecho', 'concluded': 'Concluido', 'finalized': 'Finalizado'
  };

  useEffect(() => {
    const loadRegistry = async () => {
        const local = localStorage.getItem('radar_patients');
        if (local) setRegistry(JSON.parse(local));
    };
    loadRegistry();
  }, []);

  const triggerToast = (msg: string) => {
    setToastMessage(msg);
    setShowToast(true);
  };

  const saveRegistry = (newRegistry: PatientData[]) => {
    setRegistry(newRegistry);
    localStorage.setItem('radar_patients', JSON.stringify(newRegistry));
  };

  const deleteRecord = (id: string) => {
    if(!confirm("¿Estás seguro?")) return;
    const updated = registry.filter(r => r.id !== id);
    saveRegistry(updated);
    triggerToast("Registro eliminado");
  };

  const toggleStatus = (id: string) => {
    const updated = registry.map(r => r.id === id && r.status === 'pending' ? { ...r, status: 'sent' as const } : r);
    saveRegistry(updated);
  };

  const handleGenerateAndSend = async (isResend: boolean = false) => {
    if (!patient.nombre || !patient.email) return alert("Nombre y Email son requeridos.");

    const fullPhone = phoneBody ? `${phonePrefix}${phoneBody}`.trim() : '';
    const now = Date.now();
    const accessPin = Math.floor(1000 + Math.random() * 9000).toString();

    const payload = { 
      nombre: patient.nombre, email: patient.email, telefono: fullPhone, 
      edad: patient.edad, sexo: patient.sexo, coordinatorEmail: profile.email, timestamp: now
    };

    try {
        const idEncoded = safeBtoa(JSON.stringify(payload));
        const baseUrl = "https://el-cuestionario-espejo.vercel.app/";
        const url = `${baseUrl}#/session?p=${idEncoded}`;

        setLinkGenerated(url);

        const newRecord: PatientData = { 
          ...patient as PatientData, 
          telefono: fullPhone, id: idEncoded, status: 'pending', dateSent: now, accessPin 
        };

        await DataService.savePatient(newRecord);
        saveRegistry([...registry, newRecord]);

        let body = `Hola ${patient.nombre.split(' ')[0]},\n\nAquí tienes tu enlace directo para realizar el Cuestionario Espejo:\n${url}\n\nIMPORTANTE: Tu clave de acceso personal para la conclusión final será: ${accessPin}. No la pierdas, ya que la necesitarás más adelante.\n\nGracias.`;
        if (isResend) body = `Hola ${patient.nombre.split(' ')[0]},\n\nHemos actualizado tu Cuestionario Espejo. Accede aquí:\n${url}\n\nRecuerda tu clave de resultados: ${accessPin}`;

        if (sendMethods.whatsapp && fullPhone) window.open(`https://wa.me/${fullPhone.replace(/\D/g, '')}?text=${encodeURIComponent(body)}`, '_blank');
        if (sendMethods.email) window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(patient.email)}&su=${encodeURIComponent("Tu Cuestionario Espejo")}&body=${encodeURIComponent(body)}`, '_blank');

        triggerToast(isResend ? "Cuestionario reenviado" : "Enlace generado y PIN enviado.");
    } catch (error) { alert("Error al generar el enlace."); }
  };

  const handleResendFromDetails = () => {
      if (!selectedPatientDetails) return;
      const p = selectedPatientDetails;
      setPatient({ nombre: p.nombre, email: p.email, edad: p.edad, sexo: p.sexo, telefono: p.telefono, observaciones: p.observaciones });
      setSelectedPatientDetails(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      setTimeout(() => handleGenerateAndSend(true), 500);
  };

  const openConclusionModal = (p: PatientData) => {
    setSelectedPatientConclusion(p);
    setEditingConclusion(p.finalConclusion || "");
    setEditingAudio(p.audioConclusion);
  };

  const handleSaveConclusion = async () => {
    if (!selectedPatientConclusion) return;
    const updatedPatient = { ...selectedPatientConclusion, finalConclusion: editingConclusion, audioConclusion: editingAudio };
    await DataService.savePatient(updatedPatient);
    const updatedReg = registry.map(r => r.id === updatedPatient.id ? updatedPatient : r);
    saveRegistry(updatedReg);
    setSelectedPatientConclusion(updatedPatient);
    triggerToast("Conclusión guardada");
  };

  const getConclusionUrlAndBody = (p: PatientData) => {
    const baseUrl = "https://el-cuestionario-espejo.vercel.app/";
    const url = `${baseUrl}#/conclusion?id=${encodeURIComponent(p.id)}`;
    const body = `Hola ${p.nombre.split(' ')[0]},\n\nYa están disponibles tus resultados y la conclusión de tu Cuestionario Espejo.\n\nPuedes acceder aquí:\n${url}\n\nRecuerda usar la clave de 4 dígitos que se te entregó inicialmente.`;
    return { url, body };
  };

  const filteredRegistry = registry.filter(p => {
      const matchesSearch = searchTerm === '' || p.nombre.toLowerCase().includes(searchTerm.toLowerCase()) || p.email.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'all' || p.status === filterStatus;
      return matchesSearch && matchesStatus;
  });

  return (
    <div className="min-h-screen overflow-y-auto relative">
      <div className="absolute inset-0 pointer-events-none opacity-20 bg-cover bg-center -z-10" style={{backgroundImage: "url('https://images.unsplash.com/photo-1516550893923-42d28e5677af?q=80&w=2070&auto=format&fit=crop')"}}></div>

      {selectedPatientConclusion && (
          <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4 overflow-y-auto backdrop-blur-sm">
             <Card className="w-full max-w-3xl max-h-[90vh] flex flex-col">
                <div className="flex justify-between items-center mb-6 border-b pb-4">
                    <h2 className="text-2xl font-bold text-slate-800"><i className="fas fa-brain text-purple-600 mr-2"></i> Gestión de Conclusión</h2>
                    <button onClick={() => setSelectedPatientConclusion(null)} className="text-slate-400 hover:text-red-500 text-2xl"><i className="fas fa-times"></i></button>
                </div>

                <div className="flex-1 overflow-y-auto mb-6 pr-2">
                    <div className="flex justify-between items-center mb-6">
                        <div className="flex gap-4 items-center">
                            <label className="cursor-pointer bg-slate-100 hover:bg-slate-200 text-slate-600 px-4 py-3 rounded-xl font-bold text-sm border border-slate-200">
                                <i className="fas fa-microphone mr-2"></i> Subir MP3 Personal
                                <input type="file" accept="audio/*" onChange={(e) => {
                                    const file = e.target.files?.[0];
                                    if (file && file.size <= 1048576) {
                                        const reader = new FileReader();
                                        reader.onload = (ev) => setEditingAudio(ev.target?.result as string);
                                        reader.readAsDataURL(file);
                                    } else if (file) alert("Max 1MB");
                                }} className="hidden" />
                            </label>
                            {editingAudio ? <span className="text-xs font-bold text-green-600"><i className="fas fa-check"></i> Audio cargado</span> : <span className="text-xs text-slate-900 font-bold">Sin audio</span>}
                        </div>

                        <button 
                            onClick={() => {
                                const { url } = getConclusionUrlAndBody(selectedPatientConclusion);
                                window.open(url, '_blank');
                            }}
                            className="bg-slate-100 hover:bg-slate-200 text-slate-600 px-4 py-3 rounded-xl font-bold text-sm border border-slate-200"
                        >
                            <i className="fas fa-external-link-alt mr-2"></i> Ver Informe del Paciente
                        </button>
                    </div>

                    <textarea className="w-full h-[32rem] p-4 rounded-xl border-2 border-slate-200 outline-none text-base leading-relaxed resize-none bg-white text-slate-700" value={editingConclusion} onChange={(e) => setEditingConclusion(e.target.value)} placeholder="Redacta aquí la conclusión final..." />
                </div>

                <div className="flex gap-4 pt-4 border-t">
                    <Button onClick={handleSaveConclusion} className="flex-1 bg-purple-600 shadow-purple-200">Guardar</Button>
                    <div className="flex gap-2 flex-1">
                        <Button onClick={() => {
                            const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
                            window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(selectedPatientConclusion.email)}&su=${encodeURIComponent("Resultados - Espejo")}&body=${encodeURIComponent(body)}`, '_blank');
                        }} variant="secondary" className="flex-1 bg-green-600">Email</Button>
                        <Button onClick={() => {
                            const { body } = getConclusionUrlAndBody(selectedPatientConclusion);
                            window.open(`https://wa.me/${selectedPatientConclusion.telefono.replace(/\D/g, '')}?text=${encodeURIComponent(body)}`, '_blank');
