import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { DataService } from '../services/dataService'; 
import { PatientData, Voice, Question, GlobalConfig, DualAudio } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_CONFIG: GlobalConfig = {
  welcomeText: "Hola soy el Radar que ahora te va a guiar...",
  welcomeAudio: {},
  nameQuestionText: "¿Cómo te llamas?...",
  nameQuestionAudio: {},
  startText: "Bienvenido {{nombre}}...",
  startAudio: {},
  finishText: "Tus respuestas y la valoración están listas...",
  finishAudio: {},
  afterSendText: "Envio realizado {{nombre}}...",
  afterSendAudio: {},
  defaultVoiceMode: Voice.FEMALE
};

const BACKGROUNDS = { intro: 'assets/fondo1.webp', verification: 'assets/fondo2.webp', general: 'assets/fondo3.webp' };
const AUDIO_START_DELAY = 800;

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);
  const [globalConfig, setGlobalConfig] = useState<GlobalConfig>(() => {
    try { const saved = localStorage.getItem('radar_global_config'); return saved ? JSON.parse(saved) : DEFAULT_CONFIG; } catch(e) { return DEFAULT_CONFIG; }
  });

  const [questions, setQuestions] = useState<Question[]>(INITIAL_QUESTIONS);

  useEffect(() => {
    const fetchData = async () => {
        const remoteQuestions = await DataService.getQuestions();
        if (remoteQuestions && remoteQuestions.length > 0) setQuestions(remoteQuestions);
        const remoteConfig = await DataService.getGlobalConfig(DEFAULT_CONFIG);
        setGlobalConfig(remoteConfig);
    };
    fetchData();
  }, []);

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish' | 'locked'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(globalConfig.defaultVoiceMode);
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);

  const saveQuestionChanges = async () => {
    if (!editingQuestion) return;
    const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
    setQuestions(updated);
    await DataService.saveQuestions(updated); // Guardado centralizado
    setEditingQuestion(null);
  };

  const handleAnswer = (key: string) => {
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    const nextIdx = currentQuestionIndex + 1;
    if (nextIdx >= questions.length) setStep('finish');
    else setCurrentQuestionIndex(nextIdx);
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden bg-[#faf9f6]">
      <div className="fixed inset-0 z-0 bg-cover bg-center" style={{ backgroundImage: `url('${BACKGROUNDS.general}')` }}>
        <div className="absolute inset-0 bg-white/40 backdrop-blur-sm"></div>
      </div>

      <header className="backdrop-blur-md border-b p-4 sticky top-0 z-50">
        <div className="max-w-xl mx-auto flex justify-between items-center">
          <Logo size="sm" />
          <Button variant="outline" onClick={onExitEditor}><i className="fas fa-times"></i></Button>
        </div>
      </header>

      <main className="flex-1 max-w-2xl mx-auto w-full px-4 pt-8 pb-32 relative z-10">
        {step === 'intro' ? (
          <div className="min-h-[60vh] flex flex-col items-center justify-center">
            <Button onClick={() => setStep('verification')} className="scale-125">Empezar Cuestionario</Button>
          </div>
        ) : step === 'verification' ? (
            <div className="space-y-6">
                <Card>
                    <p className="font-bold text-lg mb-4">¿Cómo te llamas?</p>
                    <Input label="Tu nombre" onChange={(e) => setCurrentPatientData({...currentPatientData, nombre: e.target.value})} />
                    <Button onClick={() => setStep('questionnaire')}>Confirmar</Button>
                </Card>
            </div>
        ) : step === 'questionnaire' && questions[currentQuestionIndex] ? (
          <div className="space-y-6">
            <ProgressBar current={currentQuestionIndex + 1} total={questions.length} />
            <Card className="p-8 relative">
                <h2 className="text-2xl font-bold">{questions[currentQuestionIndex].scenario}</h2>
                {isEditorMode && <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute top-2 right-2 text-blue-600"><i className="fas fa-edit"></i></button>}
            </Card>
            <div className="space-y-4">
                {questions[currentQuestionIndex].options.map(opt => (
                    <button key={opt.key} onClick={() => handleAnswer(opt.key)} className="w-full text-left p-6 rounded-2xl border-2 bg-white/80 hover:border-blue-400 flex items-center gap-4">
                        <span className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-black text-sm">{opt.key.toUpperCase()}</span>
                        <span className="font-bold">{opt.text}</span>
                    </button>
                ))}
            </div>
          </div>
        ) : step === 'finish' ? (
            <Card className="text-center py-16">
                <h2 className="text-3xl font-bold mb-6">Cuestionario Finalizado</h2>
                <Button onClick={onExitEditor}>Cerrar</Button>
            </Card>
        ) : null}
      </main>

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4">
            <Card className="max-w-xl w-full">
                <h3 className="text-xl font-bold mb-4">Editar Situación</h3>
                <textarea className="w-full p-4 border rounded-xl mb-4 h-32" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                <div className="flex gap-4">
                    <Button onClick={saveQuestionChanges} className="flex-1">Guardar</Button>
                    <Button variant="outline" onClick={() => setEditingQuestion(null)} className="flex-1">Cancelar</Button>
                </div>
            </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo } from './UI';
import { PatientData } from '../types';
import { DataService } from '../services/dataService';

interface ConclusionPatientViewProps {
  patientId: string;
}

export const ConclusionPatientView: React.FC<ConclusionPatientViewProps> = ({ patientId }) => {
  const [patient, setPatient] = useState<PatientData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [unlocked, setUnlocked] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [pinError, setPinError] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const loadData = async () => {
        const found = await DataService.getPatient(patientId);
        if (found) setPatient(found);
        else setError("Informe no encontrado.");
        setLoading(false);
    };
    loadData();
  }, [patientId]);

  const verifyPin = () => {
      if (patient && pinInput === patient.accessPin) {
          setUnlocked(true);
      } else {
          setPinError(true);
          setTimeout(() => setPinError(false), 2000);
      }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-[#faf9f6]"><div className="animate-spin w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full"></div></div>;

  if (!unlocked && patient) {
    return (
        <div className="min-h-screen flex items-center justify-center p-4 relative font-sans">
             <div className="absolute inset-0 z-0 bg-cover bg-center opacity-60" style={{ backgroundImage: "url('assets/fondoconclusion.webp')" }}></div>
             <Card className="max-w-md w-full p-10 relative z-10 text-center shadow-2xl border-white/50 backdrop-blur-md bg-white/90">
                <Logo />
                <div className="mt-8 mb-6">
                    <h3 className="text-xl font-bold text-blue-900 mb-2">Acceso Protegido</h3>
                    <p className="text-sm text-slate-500">Introduce la clave de 4 dígitos que recibiste para ver tu conclusión.</p>
                </div>
                <div className="mb-8">
                    <input 
                        type="password" 
                        maxLength={4} 
                        className={`w-full text-center text-4xl tracking-[0.5em] p-4 rounded-2xl border-2 outline-none transition-all ${pinError ? 'border-red-500 bg-red-50' : 'border-blue-100 focus:border-blue-500'}`}
                        placeholder="****"
                        value={pinInput}
                        onChange={e => setPinInput(e.target.value.replace(/\D/g, ''))}
                        onKeyPress={e => e.key === 'Enter' && pinInput.length === 4 && verifyPin()}
                    />
                    {pinError && <p className="text-red-500 text-xs font-bold mt-2">Clave incorrecta</p>}
                </div>
                <Button onClick={verifyPin} disabled={pinInput.length < 4} className="w-full py-4 text-lg">Entrar al Informe</Button>
            </Card>
        </div>
    );
  }

  if (error || !patient) return <div className="min-h-screen flex items-center justify-center bg-[#faf9f6]"><h2>{error}</h2></div>;

  return (
    <div className="min-h-screen bg-[#faf9f6] relative font-sans">
        <div className="absolute inset-0 z-0 bg-cover bg-center opacity-80" style={{ backgroundImage: "url('assets/fondoconclusion.webp')" }}>
            <div className="absolute inset-0 bg-white/40 backdrop-blur-sm"></div>
        </div>
        {patient.audioConclusion && <audio ref={audioRef} src={patient.audioConclusion} className="hidden" />}

        <div className="max-w-4xl mx-auto relative z-10 p-4 md:p-8">
            <div className="mb-10 text-center"><Logo /></div>

            <Card className="mb-12 border-none shadow-2xl overflow-hidden relative animate-in zoom-in-95 duration-700 bg-white/95">
                <div className="bg-gradient-to-r from-blue-900 to-indigo-900 p-8 md:p-14 text-white relative">
                    <div className="relative z-10">
                        <h2 className="text-3xl md:text-5xl font-friendly font-bold mb-4 leading-tight">Análisis Terapéutico</h2>
                        <p className="text-blue-100 text-lg">Preparado para: <span className="font-bold text-white text-xl ml-2">{patient.nombre}</span></p>
                    </div>
                    {patient.audioConclusion && (
                        <button onClick={() => audioRef.current?.play()} className="absolute top-8 right-8 z-20 w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-lg text-blue-600 hover:scale-110 active:scale-95 transition-all cursor-pointer">
                            <i className="fas fa-play text-2xl ml-1"></i>
                        </button>
                    )}
                </div>

                <div className="p-8 md:p-14">
                    <div className="prose prose-lg prose-slate max-w-none text-slate-700 leading-loose whitespace-pre-line text-justify font-medium">
                        {patient.finalConclusion || patient.conversationSummary || "Informe en preparación."}
                    </div>
                </div>
            </Card>

            <div className="text-center space-y-12 mb-24">
                <div className="space-y-4">
                    <h3 className="text-3xl md:text-4xl font-friendly font-bold text-slate-800 leading-tight">Es el momento de tomar el control</h3>
                    <p className="text-slate-600 text-lg max-w-2xl mx-auto font-medium">Permítenos guiarte paso a paso en tu transformación.</p>
                </div>
                <div className="flex flex-col md:flex-row items-center justify-center gap-6 px-4">
                    <button onClick={() => window.location.href="https://example.com/reserva"} className="w-full md:w-auto px-10 py-6 text-xl font-black rounded-3xl bg-gradient-to-r from-blue-600 to-indigo-700 text-white shadow-2xl hover:scale-105 active:scale-95 transition-all animate-pulse border-none cursor-pointer">Reservar terapia</button>
                    <button onClick={() => window.location.href="https://example.com/terapias"} className="w-full md:w-auto px-10 py-6 text-lg font-bold rounded-3xl bg-white text-indigo-700 border-2 border-indigo-100 shadow-xl hover:bg-indigo-50 transition-all cursor-pointer">Conocer más sobre las terapias que necesito</button>
                </div>
            </div>
        </div>
    </div>
  );
};

