  const [globalConfig, setGlobalConfig] = useState<GlobalConfig>(DEFAULT_CONFIG);

  // Inicializamos con preguntas por defecto, pero DataService las sobreescribirá inmediatamente
  const [questions, setQuestions] = useState<Question[]>(INITIAL_QUESTIONS);

  useEffect(() => {
    const fetchData = async () => {
        // OBLIGATORIO: Cargar las preguntas personalizadas del servicio (Local/Firebase)
        // Esto asegura que si el coordinador editó, el paciente vea ESAS preguntas.
        const remoteQuestions = await DataService.getQuestions();
        if (remoteQuestions && remoteQuestions.length > 0) {
            setQuestions(remoteQuestions);
        }

        const remoteConfig = await DataService.getGlobalConfig(DEFAULT_CONFIG);
        setGlobalConfig(remoteConfig);
    };
    fetchData();
  }, []);

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish' | 'locked'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(globalConfig.defaultVoiceMode);
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);

  const saveQuestionChanges = async () => {
    if (!editingQuestion) return;
    const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
    setQuestions(updated);
    // GUARDADO CRÍTICO: Guardamos en DataService para que persista para los pacientes
    await DataService.saveQuestions(updated); 
    setEditingQuestion(null);
  };

  const handleAnswer = (key: string) => {
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    const nextIdx = currentQuestionIndex + 1;
    if (nextIdx >= questions.length) setStep('finish');
    else setCurrentQuestionIndex(nextIdx);
  };

  // ... (Resto del código de UI sin cambios estructurales profundos, solo renderizado) ...
  // Simplifico el renderizado para no borrar tu código, mantengo la estructura visual:

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden bg-[#faf9f6]">
      <div className="fixed inset-0 z-0 bg-cover bg-center" style={{ backgroundImage: `url('${BACKGROUNDS.general}')` }}>
        <div className="absolute inset-0 bg-white/40 backdrop-blur-sm"></div>
      </div>

      <header className="backdrop-blur-md border-b p-4 sticky top-0 z-50">
        <div className="max-w-xl mx-auto flex justify-between items-center">
          <Logo size="sm" />
          <Button variant="outline" onClick={onExitEditor}><i className="fas fa-times"></i></Button>
        </div>
      </header>

      <main className="flex-1 max-w-2xl mx-auto w-full px-4 pt-8 pb-32 relative z-10">
        {step === 'intro' ? (
          <div className="min-h-[60vh] flex flex-col items-center justify-center">
            <Button onClick={() => setStep('verification')} className="scale-125">Empezar Cuestionario</Button>
          </div>
        ) : step === 'verification' ? (
            <div className="space-y-6">
                <Card>
                    <p className="font-bold text-lg mb-4">¿Cómo te llamas?</p>
                    <Input label="Tu nombre" onChange={(e) => setCurrentPatientData({...currentPatientData, nombre: e.target.value})} />
                    <Button onClick={() => setStep('questionnaire')}>Confirmar</Button>
                </Card>
            </div>
        ) : step === 'questionnaire' && questions[currentQuestionIndex] ? (
          <div className="space-y-6">
            <ProgressBar current={currentQuestionIndex + 1} total={questions.length} />
            <Card className="p-8 relative">
                <h2 className="text-2xl font-bold">{questions[currentQuestionIndex].scenario}</h2>
                {isEditorMode && <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute top-2 right-2 text-blue-600"><i className="fas fa-edit"></i></button>}
            </Card>
            <div className="space-y-4">
                {questions[currentQuestionIndex].options.map(opt => (
                    <button key={opt.key} onClick={() => handleAnswer(opt.key)} className="w-full text-left p-6 rounded-2xl border-2 bg-white/80 hover:border-blue-400 flex items-center gap-4">
                        <span className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-black text-sm">{opt.key.toUpperCase()}</span>
                        <span className="font-bold">{opt.text}</span>
                    </button>
                ))}
            </div>
          </div>
        ) : step === 'finish' ? (
            <Card className="text-center py-16">
                <h2 className="text-3xl font-bold mb-6">Cuestionario Finalizado</h2>
                <Button onClick={onExitEditor}>Cerrar</Button>
            </Card>
        ) : null}
      </main>

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4">
            <Card className="max-w-xl w-full">
                <h3 className="text-xl font-bold mb-4">Editar Situación</h3>
