                    <Button variant="outline" onClick={() => setEditingQuestion(null)} className="flex-1">Cancelar</Button>
                </div>
            </Card>
        </div>
      )}
    </div>
  );
};

import { db } from './firebase';
import { doc, getDoc, collection, getDocs, setDoc } from 'firebase/firestore';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { Question, GlobalConfig, PatientData } from '../types';

export const DataService = {

  async getQuestions(): Promise<Question[]> {
    let questions: Question[] = [];
    if (db) {
      try {
        const docRef = doc(db, 'questionnaires', 'active');
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
          const data = docSnap.data();
          if (data.questions && Array.isArray(data.questions)) {
             questions = data.questions.map((q: any) => ({
                 ...q,
                 scenario: q.text || q.scenario || "Pregunta sin texto",
                 options: q.answers || q.options || [],
                 id: q.id ? String(q.id) : Date.now().toString()
             }));
          }
        }
      } catch (error) {
        console.warn("Fallo lectura Firebase (questionnaires/active)", error);
      }
    }

    // Si no hay preguntas de Firebase, buscamos en LocalStorage
    if (questions.length === 0) {
      try {
        const local = localStorage.getItem('radar_custom_questions');
        if (local) questions = JSON.parse(local);
      } catch (e) {}
    }

    // Si no hay nada, devolvemos las iniciales
    return questions.length > 0 ? questions : INITIAL_QUESTIONS;
  },

  async saveQuestions(questions: Question[]): Promise<void> {
    // Guardamos siempre en LocalStorage como backup inmediato
    localStorage.setItem('radar_custom_questions', JSON.stringify(questions));

    // Intentamos guardar en Firebase para sincronización global
    if (db) {
      try {
        await setDoc(doc(db, 'questionnaires', 'active'), { questions, updatedAt: Date.now() });
      } catch (e) {
        console.error("Error saving questions to Firebase", e);
      }
    }
  },

  async savePatient(patient: PatientData): Promise<void> {
    const local = JSON.parse(localStorage.getItem('radar_patients') || '[]');
    const updated = local.filter((p: any) => p.id !== patient.id);
    updated.push(patient);
    localStorage.setItem('radar_patients', JSON.stringify(updated));
    if (db) {
      try {
        await setDoc(doc(db, 'patients', patient.id), patient);
      } catch (e) {
        console.error("Error saving patient", e);
      }
    }
  },

  async getPatient(id: string): Promise<PatientData | null> {
    if (db) {
      try {
        const snap = await getDoc(doc(db, 'patients', id));
        if (snap.exists()) return snap.data() as PatientData;
      } catch (e) {}
    }
    const local = JSON.parse(localStorage.getItem('radar_patients') || '[]');
    return local.find((p: any) => p.id === id) || null;
  },

  async getGlobalConfig(defaultConfig: GlobalConfig): Promise<GlobalConfig> {
      let config = { ...defaultConfig };
      let foundRemote = false;
      if (db) {
          try {
              const querySnapshot = await getDocs(collection(db, 'config'));
              querySnapshot.forEach((doc) => {
                  if (doc.id === 'global_config') {
                      config = { ...config, ...doc.data() };
                      foundRemote = true;
                  }
              });
          } catch (e) {}
      }
      if (!foundRemote) {
          try {
            const local = localStorage.getItem('radar_global_config');
            if (local) config = { ...config, ...JSON.parse(local) };
          } catch (e) {}
      }
      return config;
  }
};

