                    <div className="flex justify-between items-center mb-6">
                        <div className="flex gap-4 items-center">
                            <label className="cursor-pointer bg-slate-100 hover:bg-slate-200 text-slate-600 px-4 py-3 rounded-xl font-bold text-sm transition-colors border border-slate-200">
