  const [registry, setRegistry] = useState<PatientData[]>([]);
  const [toastMessage, setToastMessage] = useState('');
  const [showToast, setShowToast] = useState(false);

  // Estados para filtros de fecha
  const [dateStart, setDateStart] = useState('');
  const [dateEnd, setDateEnd] = useState('');

  const [selectedPatientResults, setSelectedPatientResults] = useState<PatientData | null>(null);
  const [selectedPatientConclusion, setSelectedPatientConclusion] = useState<PatientData | null>(null);

  const [selectedPatientDetails, setSelectedPatientDetails] = useState<PatientData | null>(null); 
  const [isEditingDetails, setIsEditingDetails] = useState(false);
  const [tempPatientDetails, setTempPatientDetails] = useState<PatientData | null>(null);

  const [editingConclusion, setEditingConclusion] = useState('');
  const [editingAudio, setEditingAudio] = useState<string | undefined>(undefined);

  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');

  const statusLabels: Record<string, string> = {
      'all': 'Todos',
      'pending': 'Pendiente',
      'sent': 'Enviado',
      'viewed': 'Visto',
      'completed': 'Hecho',
      'concluded': 'Concluido',
      'finalized': 'Finalizado'
  };

  useEffect(() => {
    try {
        const saved = localStorage.getItem('radar_patients');
        if (saved) {
            setRegistry(JSON.parse(saved));
        } else {
            const sample: PatientData = {
                id: 'sample-martin',
                nombre: 'Martín ejemplo',
                email: 'martin@ejemplo.com',
                edad: '34',
                sexo: 'Hombre',
                observaciones: 'Registro de ejemplo generado automáticamente. Este perfil muestra cómo se visualiza un paciente con todas las preguntas completadas.',
                telefono: '+34600123456',
                status: 'completed',
                dateSent: Date.now() - 86400000,
                dateAnswered: Date.now() - 3600000,
                answers: {
                    "1": "b",   // Malentendido -> Reconstruir escena
                    "1.1": "b", // Tiempo -> Varias horas
                    "2": "b",   // Semana -> Miedo a no gestionar
                    "2.2": "c", // Frecuencia -> Constante
                    "3": "b",   // Silencio -> Aterra, bucles
                    "3.3": "4", // Compromiso -> 4/10
                    "4": "b",   // Espera mensaje -> Repaso mensaje
                    "4.4": "b", // Desaparece? -> No, cuestiono
                    "5": "c",   // Grupo amigos -> No pertenencia
                    "6": "b",   // Discusión -> Rabia desborda
                    "7": "d",   // Espejo -> Hace mucho no me gusta
                    "8": "c",   // Levantarse -> Hace tiempo
                    "9": "c",   // Gustos -> Obligación
                    "10": "b",  // Disfrute -> En ocasiones
                    "11": "e",  // Dormir -> Temo ir a dormir (Rumiación)
                    "12": "d"   // Calma -> Ansiedad en situaciones complejas
                },
                conversationSummary: INTERNAL_CLINICAL_EXAMPLE,
                finalConclusion: EXTERNAL_PATIENT_EXAMPLE,
                conclusionViews: 0,
                accessPin: "1234"
            };
            setRegistry([sample]);
        }
    } catch (e) {
        console.error("Error cargando registros", e);
    }
  }, []);

  const triggerToast = (msg: string) => {
    setToastMessage(msg);
    setShowToast(true);
  };

  const saveRegistry = (newRegistry: PatientData[]) => {
    setRegistry(newRegistry);
    localStorage.setItem('radar_patients', JSON.stringify(newRegistry));
  };

  const deleteRecord = (id: string) => {
    if(!confirm("¿Estás seguro? Se borrarán todos los datos del paciente.")) return;
    const updated = registry.filter(r => r.id !== id);
    saveRegistry(updated);
    triggerToast("Registro eliminado correctamente");
  };

  const toggleStatus = (id: string) => {
    const updated = registry.map(r => {
      if (r.id === id) {
        if (r.status === 'pending') {
            return { ...r, status: 'sent' as const };
        } else if (r.status === 'sent') {
            return { ...r, status: 'pending' as const };
        }
      }
      return r;
    });

    saveRegistry(updated);

    const patient = registry.find(r => r.id === id);
    if (patient) {
        if (patient.status === 'pending') triggerToast("Estado actualizado a ENVIADO");
        else if (patient.status === 'sent') triggerToast("Estado actualizado a PENDIENTE");
    }
  };

  const handleGenerateAndSend = (isResend: boolean = false) => {
    if (!patient.nombre || !patient.email) return alert("Nombre y Email son requeridos.");

    const fullPhone = phoneBody ? `${phonePrefix}${phoneBody}`.trim() : '';
    const now = Date.now();

    // Generar PIN aleatorio de 4 dígitos
    const accessPin = Math.floor(1000 + Math.random() * 9000).toString();

    const payload = { 
      nombre: patient.nombre, 
      email: patient.email,
      telefono: fullPhone, 
      edad: patient.edad, 
      sexo: patient.sexo, 
      coordinatorEmail: profile.email, 
      timestamp: now
    };

    try {
        const idEncoded = safeBtoa(JSON.stringify(payload));
        const baseUrl = "https://el-cuestionario-espejo.vercel.app/";
        const url = `${baseUrl}#/session?p=${idEncoded}`;

        setLinkGenerated(url);

        const newRecord: PatientData = { 
          ...patient as PatientData, 
          telefono: fullPhone,
          id: idEncoded, 
          status: 'pending', 
          dateSent: now,
          accessPin: accessPin // Guardamos el PIN
        };

        saveRegistry([...registry, newRecord]);

        let subject = "Tu enlace para el Cuestionario Espejo";
        let body = `Hola ${patient.nombre.split(' ')[0]},\n\nAquí tienes tu enlace directo para realizar el Cuestionario Espejo:\n${url}\n\nIMPORTANTE: Tu clave de acceso personal para ver los resultados finales será: ${accessPin}\nPor favor, guárdala bien, ya que la necesitarás obligatoriamente más adelante para desbloquear la conclusión.\n\nGracias.`;

        if (isResend) {
            subject = "Actualización Importante: Cuestionario Espejo";
            body = `Hola ${patient.nombre.split(' ')[0]},\n\nHemos actualizado tu cuestionario. Accede aquí:\n${url}\n\nRecuerda tu clave de resultados: ${accessPin}\n\nUn cordial saludo,\nEl equipo de Naveguemos Juntos.`;
        }

        const smsBody = `Hola ${patient.nombre.split(' ')[0]}, enlace: ${url} . CLAVE DE ACCESO: ${accessPin} (Guárdala).`;

        if (sendMethods.whatsapp && fullPhone) {
          const cleanPhone = fullPhone.replace(/\D/g, '');
          window.open(`https://wa.me/${cleanPhone}?text=${encodeURIComponent(body)}`, '_blank');
        }

        if (sendMethods.email) {
          const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(patient.email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
          window.open(gmailUrl, '_blank');
        }

        if (sendMethods.sms && fullPhone) {
          window.open(`sms:${fullPhone}?body=${encodeURIComponent(smsBody)}`, '_blank');
        }

        triggerToast(isResend ? "Cuestionario reenviado con PIN" : `Enlace generado. PIN: ${accessPin}`);

    } catch (error) {
        console.error("Error generando enlace", error);
        alert("Error al generar el enlace.");
    }
  };

  const handleResendFromDetails = () => {
      if (!selectedPatientDetails) return;

      const p = selectedPatientDetails;
      setPatient({
          nombre: p.nombre,
          email: p.email,
          edad: p.edad,
          sexo: p.sexo,
          telefono: p.telefono,
          observaciones: p.observaciones
      });

      if (p.telefono && p.telefono.length > 3) {
          setPhonePrefix(p.telefono.substring(0, 3));
          setPhoneBody(p.telefono.substring(3));
      }

      setSelectedPatientDetails(null);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      setTimeout(() => handleGenerateAndSend(true), 500);
  };

  const openResultsModal = (p: PatientData) => {
    setSelectedPatientResults(p);
  };

  const openConclusionModal = (p: PatientData) => {
    setSelectedPatientConclusion(p);
    setEditingConclusion(p.finalConclusion || EXTERNAL_PATIENT_EXAMPLE);
    setEditingAudio(p.audioConclusion);
  };

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          if (file.size > 1048576) {
              alert("El archivo de audio es demasiado grande. Por favor, usa un clip corto o comprimido (Max 1MB).");
              return;
          }
          const reader = new FileReader();
          reader.onload = (ev) => {
              setEditingAudio(ev.target?.result as string);
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSaveConclusion = () => {
    if (!selectedPatientConclusion) return;
    const updated = registry.map(r => {
        if (r.id === selectedPatientConclusion.id) {
            return { 
                ...r, 
                finalConclusion: editingConclusion,
                audioConclusion: editingAudio 
            };
        }
        return r;
    });
    saveRegistry(updated);
    setSelectedPatientConclusion({ ...selectedPatientConclusion, finalConclusion: editingConclusion, audioConclusion: editingAudio });
    triggerToast("Conclusión y audio guardados correctamente");
  };

  const handleEditDetails = () => {
      if (selectedPatientDetails) {
          setTempPatientDetails(selectedPatientDetails);
          setIsEditingDetails(true);
      }
  };

  const handleCancelEditDetails = () => {
      setIsEditingDetails(false);
      setTempPatientDetails(null);
  };

  const handleSaveDetails = () => {
      if (!tempPatientDetails) return;
      const updated = registry.map(r => r.id === tempPatientDetails.id ? tempPatientDetails : r);
      saveRegistry(updated);
      setSelectedPatientDetails(tempPatientDetails);
      setIsEditingDetails(false);
      triggerToast("Ficha actualizada correctamente");
  };

  const getConclusionUrlAndBody = (p: PatientData) => {
    const baseUrl = "https://el-cuestionario-espejo.vercel.app/";
    const url = `${baseUrl}#/conclusion?id=${encodeURIComponent(p.id)}`;
    const body = `Hola ${p.nombre.split(' ')[0]},\n\nYa están disponibles tus resultados del Cuestionario Espejo.\n\nPuedes acceder a ellos a través del siguiente enlace:\n${url}\n\nIMPORTANTE: Se te pedirá la clave numérica de 4 dígitos que se te entregó al iniciar el cuestionario (${p.accessPin || 'Consulta con tu coordinador'}).`;
    return { url, body };
  };

