                                        <span className="block text-base font-medium text-slate-800">{selectedPatientDetails.telefono || 'N/A'}</span>
                                    </div>
                                    <div>
                                        <span className="block text-xs font-bold text-slate-500 uppercase">Edad / Sexo</span>
